INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'eso', '{1}', '["Le matin, je me réveille à sept heures","Ensuite, je prends une douche rapide dans la salle de bains","Puis, je mange des céréales avec du lait au petit déjeuner","Après, je mets mon uniforme et prépare mon sac","Finalement, je sors de la maison pour aller à l''école"]'),
('frances', 'eso', '{1}', '["D''abord, mon père prépare le café dans la cuisine","Ensuite, ma mère réveille mes frères et soeurs","Puis, toute la famille se retrouve autour de la table","Après, nous mangeons des tartines avec de la confiture","Finalement, chacun part travailler ou étudier pour la journée"]'),
('frances', 'eso', '{1}', '["Le lundi matin, j''arrive à l''école avec mes amis","Ensuite, nous entrons dans la classe et saluons le professeur","Puis, nous sortons nos cahiers et nos stylos pour commencer","Après, le professeur explique la nouvelle leçon de mathématiques","Finalement, nous faisons des exercices dans nos cahiers d''activités"]'),
('frances', 'eso', '{1}', '["À midi, la cloche sonne pour annoncer la pause déjeuner","Ensuite, nous descendons tous au réfectoire de l''école","Puis, nous prenons un plateau et choisissons notre repas","Après, nous mangeons et discutons avec nos camarades de classe","Finalement, nous avons quinze minutes pour jouer dans la cour"]'),
('frances', 'eso', '{1}', '["Le samedi, ma famille décide d''aller au parc municipal","Ensuite, nous préparons un pique-nique avec des sandwichs et des fruits","Puis, nous marchons trente minutes pour arriver au parc","Après, nous étalons une couverture sous un grand arbre","Finalement, nous jouons au ballon jusqu''au coucher du soleil"]'),
('frances', 'eso', '{1}', '["Pour mon anniversaire, j''invite tous mes amis à la maison","Ensuite, ma mère prépare un grand gâteau au chocolat","Puis, mes amis arrivent avec des cadeaux dans les mains","Après, je souffle les bougies et tout le monde chante","Finalement, nous mangeons le gâteau et jouons à des jeux"]'),
('frances', 'eso', '{1}', '["Le soir, ma mère commence à préparer le dîner familial","Ensuite, mon père met la table avec les assiettes et verres","Puis, toute la famille s''assoit ensemble autour de la table","Après, nous mangeons en racontant notre journée à l''école","Finalement, mes frères et moi aidons à débarrasser la vaisselle"]'),
('frances', 'eso', '{1}', '["D''abord, je rentre à la maison après''une longue journée","Ensuite, je prends un goûter dans la cuisine avec mon frère","Puis, je monte dans ma chambre pour faire mes devoirs","Après, je révise mes leçons pendant environ une heure","Finalement, je joue un peu avant le dîner familial"]'),
('frances', 'eso', '{1}', '["Le professeur de français entre dans la salle de classe","Ensuite, il salue tous les élèves avec un grand sourire","Puis, il écrit la date et le titre au tableau noir","Après, il distribue des feuilles d''exercices à chaque élève","Finalement, nous travaillons en silence pendant toute la séance"]'),
('frances', 'eso', '{1}', '["Le mercredi après-midi, je vais à mon cours de musique","Ensuite, je sors mon instrument et m''installe dans la salle","Puis, le professeur nous explique le nouveau morceau à jouer","Après, nous répétons plusieurs fois jusqu''à bien le maîtriser","Finalement, nous jouons tous ensemble en formant un petit orchestre"]'),
('frances', 'eso', '{1}', '["Le dimanche, ma grand-mère vient nous rendre visite à la maison","Ensuite, elle apporte toujours des bonbons pour mes frères et moi","Puis, nous nous asseyons dans le salon pour discuter avec elle","Après, elle nous raconte des histoires de quand elle était jeune","Finalement, nous mangeons tous ensemble un bon repas familial"]'),
('frances', 'eso', '{1}', '["Avant de dormir, je range mes affaires dans ma chambre","Ensuite, je me brosse les dents devant le miroir de la salle de bains","Puis, je mets mon pyjama préféré pour la nuit","Après, ma mère vient me souhaiter une bonne nuit","Finalement, j''éteins la lumière et je m''endors tranquillement"]'),
('frances', 'eso', '{1}', '["Le matin, le réveil sonne et je sors lentement du lit","Ensuite, j''ouvre les rideaux pour laisser entrer la lumière","Puis, je fais mon lit avant de quitter la chambre","Après, je descends à la cuisine pour le petit déjeuner","Finalement, je dis au revoir à ma famille et pars"]'),
('frances', 'eso', '{1}', '["Pendant la récréation, je sors dans la cour avec mes amis","Ensuite, nous décidons de jouer au football tous ensemble","Puis, nous formons deux équipes équilibrées de cinq joueurs chacune","Après, nous courons et marquons plusieurs buts pendant le match","Finalement, la cloche sonne et nous retournons en classe"]'),
('frances', 'eso', '{1}', '["Le vendredi soir, mes parents m''emmènent au cinéma du quartier","Ensuite, nous achetons les billets et du popcorn au comptoir","Puis, nous entrons dans la salle et trouvons nos places","Après, nous regardons un film d''aventures pendant deux heures","Finalement, nous rentrons à la maison en parlant du film"]'),
('frances', 'eso', '{1}', '["Pour aller à l''école, je prépare mon sac la veille","Ensuite, je mets mes livres, cahiers et trousse à l''intérieur","Puis, je vérifie mon emploi du temps pour ne rien oublier","Après, je laisse le sac près de la porte d''entrée","Finalement, je peux dormir tranquille sans stress du lendemain"]'),
('frances', 'eso', '{1}', '["Le samedi matin, je vais au marché avec ma mère","Ensuite, nous achetons des légumes frais chez le marchand","Puis, nous passons à la boulangerie pour acheter du pain","Après, nous prenons aussi du fromage chez le crémier","Finalement, nous rentrons à la maison avec des sacs pleins"]'),
('frances', 'eso', '{1}', '["Mon petit frère apprend à faire du vélo dans le jardin","Ensuite, mon père tient le vélo pour qu''il ne tombe pas","Puis, mon frère commence à pédaler tout seul lentement","Après, il prend confiance et roule de plus en plus vite","Finalement, il fait le tour du jardin sans aucune aide"]'),
('frances', 'eso', '{1}', '["En classe d''arts plastiques, nous préparons nos pinceaux et peintures","Ensuite, le professeur nous explique le projet de la semaine","Puis, nous dessinons un paysage sur une grande feuille blanche","Après, nous coloriions notre dessin avec beaucoup d''attention","Finalement, nous accrochons nos oeuvres au mur de la classe"]'),
('frances', 'eso', '{1}', '["Pendant les vacances de Noël, toute la famille se réunit","Ensuite, nous décorons le sapin avec des boules et des guirlandes","Puis, nous mettons les cadeaux soigneusement emballés''en dessous","Après, nous attendons minuit pour pouvoir les ouvrir","Finalement, nous partageons un grand repas tous ensemble"]'),
('frances', 'eso', '{1}', '["Le matin, je choisis mes vêtements dans mon armoire","Ensuite, je mets un pull chaud parce qu''il fait froid","Puis, j''enfile un pantalon et mes chaussures préférées","Après, je vérifie mon apparence dans le miroir du couloir","Finalement, je suis prêt pour affronter une nouvelle journée"]'),
('frances', 'eso', '{1}', '["Le professeur de sport nous demande de courir dans la cour","Ensuite, nous faisons quelques échauffements pour préparer nos muscles","Puis, nous commençons une course de relais en équipes","Après, chaque élève donne le bâton à son camarade suivant","Finalement, l''équipe gagnante reçoit les félicitations du professeur"]'),
('frances', 'eso', '{1}', '["Le dimanche matin, nous allons rendre visite à mes cousins","Ensuite, nous prenons la voiture pour traverser toute la ville","Puis, nous arrivons à leur maison après''une heure de route","Après, nous jouons tous ensemble dans le grand jardin","Finalement, nous mangeons un bon repas préparé par ma tante"]'),
('frances', 'eso', '{1}', '["Aujourd''hui, nous avons un examen important de mathématiques","Ensuite, le professeur distribue les feuilles d''examen à chacun","Puis, nous lisons attentivement toutes les questions du test","Après, nous résolvons les exercices un par un avec concentration","Finalement, nous rendons notre copie à la fin de l''heure"]'),
('frances', 'eso', '{1}', '["Le soir, je prépare mes vêtements pour le lendemain matin","Ensuite, je vérifie qu''ils soient propres et bien repassés","Puis, je les pose soigneusement sur la chaise de ma chambre","Après, je place mes chaussures juste à côté de la chaise","Finalement, je vais me coucher tranquille pour la nuit"]'),
('frances', 'eso', '{1}', '["Pendant le cours de géographie, nous étudions les pays d''Europe","Ensuite, le professeur affiche une grande carte au tableau","Puis, il nous montre les capitales de chaque pays européen","Après, nous prenons des notes dans nos cahiers d''exercices","Finalement, nous faisons un petit quiz pour vérifier nos connaissances"]'),
('frances', 'eso', '{1}', '["Ma soeur a un match de basket très''important aujourd''hui","Ensuite, toute la famille va au gymnase pour la soutenir","Puis, le match commence et son équipe joue très bien","Après, ma soeur marque plusieurs paniers pendant le match","Finalement, son équipe gagne et nous fêtons la victoire ensemble"]'),
('frances', 'eso', '{1}', '["Le matin, mon chien gratte à la porte pour sortir","Ensuite, je mets sa laisse autour de son cou rapidement","Puis, nous descendons les escaliers et sortons dans la rue","Après, nous faisons une longue promenade dans le parc voisin","Finalement, nous rentrons à la maison fatigués mais contents"]'),
('frances', 'eso', '{1}', '["Pendant le cours de sciences, nous faisons une expérience intéressante","Ensuite, le professeur nous donne tous les ingrédients nécessaires","Puis, nous mélangeons les produits dans un récipient en verre","Après, nous observons la réaction chimique avec beaucoup d''attention","Finalement, nous notons nos observations dans le cahier de laboratoire"]'),
('frances', 'eso', '{1}', '["Le samedi après-midi, je vais à la bibliothèque municipale","Ensuite, je cherche un livre intéressant dans le rayon jeunesse","Puis, je m''installe à une table calme près de la fenêtre","Après, je lis tranquillement pendant environ deux heures","Finalement, j''emprunte le livre pour le terminer chez moi"]'),
('frances', 'eso', '{1}', '["Pour la fête de l''école, nous préparons un spectacle de danse","Ensuite, le professeur de musique choisit une chanson moderne","Puis, nous apprenons les pas de danse pendant les répétitions","Après, nous mettons des costumes colorés le jour du spectacle","Finalement, nous dansons devant tous les parents et amis"]'),
('frances', 'eso', '{1}', '["Aujourd''hui, c''est l''anniversaire de mon meilleur ami Pierre","Ensuite, je vais au magasin pour lui acheter un cadeau","Puis, je choisis un livre d''aventures qu''il va adorer","Après, j''emballe le cadeau avec du papier de couleur","Finalement, je le lui donne lors de sa fête d''anniversaire"]'),
('frances', 'eso', '{1}', '["Le matin, je sens une bonne odeur venant de la cuisine","Ensuite, je descends rapidement pour voir ce qui se passe","Puis, je découvre que ma mère a fait des crêpes","Après, je m''assois à la table et j''en mange trois","Finalement, je remercie ma mère pour ce délicieux petit déjeuner"]'),
('frances', 'eso', '{1}', '["Pendant la classe d''anglais, nous écoutons un dialogue audio","Ensuite, le professeur nous pose des questions sur le contenu","Puis, nous répondons en levant la main pour parler","Après, nous répétons les nouveaux mots de vocabulaire ensemble","Finalement, nous écrivons un court texte avec ces mots"]'),
('frances', 'eso', '{1}', '["Le dimanche, je veux apprendre à cuisiner avec ma mère","Ensuite, nous lavons soigneusement nos mains dans l''évier","Puis, ma mère me montre comment couper les légumes","Après, je prépare moi-même une simple salade verte","Finalement, toute la famille mange ma préparation au déjeuner"]'),
('frances', 'eso', '{1}', '["L''hiver, il commence à neiger sur toute la ville","Ensuite, je m''habille très chaudement avec un manteau et bonnet","Puis, je sors dans le jardin pour jouer dans la neige","Après, je construis un grand bonhomme de neige avec mon frère","Finalement, nous rentrons boire un chocolat chaud à la maison"]'),
('frances', 'eso', '{1}', '["Le matin, je prends mon petit déjeuner en famille","Ensuite, ma mère me rappelle de prendre mon goûter pour l''école","Puis, je mets le sandwich et un fruit dans mon sac","Après, je vérifie que je n''ai rien oublié d''important","Finalement, je dis au revoir et pars à l''école"]'),
('frances', 'eso', '{1}', '["Pendant le cours d''histoire, nous étudions les rois de France","Ensuite, le professeur projette des images de châteaux anciens","Puis, nous prenons des notes sur les dates importantes","Après, nous faisons des groupes pour discuter du sujet","Finalement, chaque groupe présente ses idées devant la classe"]'),
('frances', 'eso', '{1}', '["Le jeudi, c''est mon jour préféré de la semaine","Ensuite, je vais à mon cours de natation après l''école","Puis, je me change rapidement dans les vestiaires","Après, je nage plusieurs longueurs dans la grande piscine","Finalement, je rentre à la maison fatigué mais content"]'),
('frances', 'eso', '{1}', '["Aujourd''hui, ma classe organise une grande sortie au musée","Ensuite, nous prenons l''autobus avec tous les autres élèves","Puis, nous arrivons au musée où un guide nous attend","Après, le guide nous explique l''histoire des objets exposés","Finalement, nous rentrons à l''école avec plein de souvenirs"]'),
('frances', 'eso', '{1}', '["Le soir, je dois absolument terminer mes devoirs de français","Ensuite, je sors mon cahier et mon livre de la matière","Puis, je relis attentivement la leçon pour bien comprendre","Après, je fais tous les exercices demandés par le professeur","Finalement, je range mes affaires dans mon sac à dos"]'),
('frances', 'eso', '{1}', '["Le samedi, mon père m''emmène au stade de football","Ensuite, nous prenons le métro pour arriver plus rapidement","Puis, nous trouvons nos places dans les gradins du stade","Après, nous regardons le match en mangeant des cacahuètes","Finalement, notre équipe préférée gagne le match deux à zéro"]'),
('frances', 'eso', '{1}', '["Pendant la pause déjeuner, je rencontre mes amis dans la cantine","Ensuite, nous prenons tous le menu du jour proposé","Puis, nous nous asseyons à la même table pour discuter","Après, nous mangeons en parlant de nos activités préférées","Finalement, nous sortons pour profiter du soleil dans la cour"]'),
('frances', 'eso', '{1}', '["Le matin de Pâques, je cherche les oeufs dans le jardin","Ensuite, mes parents ont caché des oeufs en chocolat partout","Puis, je trouve un premier oeuf derrière un grand arbre","Après, je continue à chercher dans toutes les cachettes possibles","Finalement, je rentre avec un panier rempli de chocolats"]'),
('frances', 'eso', '{1}', '["Mon amie Sophie a oublié son livre de mathématiques aujourd''hui","Ensuite, je décide de partager le mien avec elle","Puis, nous nous asseyons à côté pendant tout le cours","Après, nous faisons les exercices ensemble en silence","Finalement, le professeur nous félicite pour notre bon travail"]'),
('frances', 'eso', '{1}', '["Le lundi, je commence ma journée avec un cours d''éducation physique","Ensuite, nous nous changeons dans les vestiaires de l''école","Puis, le professeur nous fait courir autour du terrain","Après, nous jouons à différents jeux sportifs ensemble","Finalement, nous prenons une douche avant le cours suivant"]'),
('frances', 'eso', '{1}', '["Pendant le week-end, je veux ranger toute ma chambre","Ensuite, je commence par enlever tous les vêtements du sol","Puis, je les plie soigneusement et les range dans l''armoire","Après, je passe l''aspirateur sur le tapis de ma chambre","Finalement, ma chambre est propre et bien organisée"]'),
('frances', 'eso', '{1}', '["Le matin, je vois qu''il pleut beaucoup dehors","Ensuite, je prends mon parapluie avant de sortir de la maison","Puis, je marche prudemment pour ne pas glisser sur le trottoir","Après, j''arrive à l''école sans être trop mouillé","Finalement, je laisse mon parapluie ouvert pour qu''il sèche"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'eso', '{2}', '["L''été dernier, j''ai passé deux semaines en Bretagne","Nous avons pris le train de nuit depuis Madrid jusqu''à Rennes","Puis nous avons loué un petit appartement près de la plage","Chaque matin, nous avons visité un village ou un monument","Finalement, nous sommes rentrés chez nous avec de merveilleux souvenirs"]'),
('frances', 'eso', '{2}', '["Hier, ma famille et moi avons décidé d''aller au restaurant","Nous avons réservé une table pour cinq personnes à huit heures","Le serveur nous a apporté le menu et expliqué les plats","J''ai choisi un steak avec des frites et une salade","Finalement, nous avons pris un délicieux dessert au chocolat"]'),
('frances', 'eso', '{2}', '["Pour préparer un gâteau au chocolat, j''ai sorti les ingrédients","Ensuite, j''ai mélangé le beurre fondu avec le sucre blanc","Puis j''ai ajouté les oeufs, la farine et le cacao","Après, j''ai mis la pâte dans un moule beurré","Finalement, j''ai cuit le gâteau au four pendant trente minutes"]'),
('frances', 'eso', '{2}', '["Le mois dernier, je suis parti en voyage scolaire à Paris","Nous avons visité la Tour Eiffel et le musée du Louvre","Ensuite, nous nous sommes promenés le long de la Seine","Puis nous avons mangé des croissants dans un café typique","Finalement, nous sommes retournés''à l''hôtel très fatigués"]'),
('frances', 'eso', '{2}', '["Samedi dernier, j''ai préparé une grande fête pour mes amis","J''ai d''abord envoyé les invitations par message une semaine avant","Ensuite, j''ai fait les courses pour acheter boissons et nourriture","Puis j''ai décoré toute la maison avec des ballons colorés","Finalement, tous mes amis sont venus et nous avons dansé"]'),
('frances', 'eso', '{2}', '["Pour prendre l''avion, nous sommes arrivés deux heures avant","Ensuite, nous avons enregistré nos valises au comptoir de la compagnie","Puis nous avons passé le contrôle de sécurité avec nos bagages","Après, nous avons attendu dans la salle d''embarquement","Finalement, nous sommes montés dans l''avion vers notre destination"]'),
('frances', 'eso', '{2}', '["L''année dernière, j''ai commencé à apprendre le piano","Mon professeur m''a d''abord enseigné les notes de base","Ensuite, j''ai pratiqué tous les jours pendant une heure","Puis j''ai appris à jouer mes premières mélodies simples","Finalement, j''ai participé à un concert à la fin de l''année"]'),
('frances', 'eso', '{2}', '["Hier matin, je me suis réveillé très''en retard pour l''école","Je me suis habillé rapidement sans même prendre mon petit déjeuner","Ensuite, j''ai couru jusqu''à l''arrêt de bus le plus proche","Le bus était déjà parti quand je suis arrivé à l''arrêt","Finalement, j''ai dû courir jusqu''à l''école à pied"]'),
('frances', 'eso', '{2}', '["Pour apprendre à nager, j''ai pris des cours pendant l''été","Le moniteur m''a d''abord expliqué comment flotter sur l''eau","Ensuite, j''ai appris à bouger les bras et les jambes","Puis j''ai essayé de nager sans aide pour la première fois","Finalement, j''ai pu traverser toute la piscine tout seul"]'),
('frances', 'eso', '{2}', '["Le week-end passé, nous avons fait une randonnée en montagne","Nous sommes partis très tôt le matin avec nos sacs à dos","Ensuite, nous avons marché pendant trois heures jusqu''au sommet","Puis nous avons pique-niqué en admirant le paysage magnifique","Finalement, nous sommes redescendus fatigués mais très''heureux"]'),
('frances', 'eso', '{2}', '["Ce matin, j''ai aidé ma mère à faire les courses","D''abord, nous avons fait une liste de ce qu''il fallait","Ensuite, nous sommes allés''au supermarché du quartier","Puis nous avons choisi les fruits, les légumes et le pain","Finalement, nous avons payé à la caisse et sommes rentrés"]'),
('frances', 'eso', '{2}', '["Pour préparer une salade niçoise, j''ai lavé tous les légumes","Ensuite, j''ai coupé les tomates et les oeufs durs en morceaux","Puis j''ai ajouté des olives noires et du thon en conserve","Après, j''ai assaisonné avec de l''huile et du vinaigre","Finalement, j''ai servi la salade avec du pain frais"]'),
('frances', 'eso', '{2}', '["Samedi dernier, je suis allé voir un match de football","J''ai pris le métro pour arriver au stade sans embouteillages","Ensuite, j''ai acheté mon billet d''entrée au guichet","Puis j''ai trouvé ma place dans les gradins du stade","Finalement, mon équipe préférée a gagné le match trois à un"]'),
('frances', 'eso', '{2}', '["L''été passé, j''ai visité la ville de Barcelone","Nous sommes arrivés''en train après''un long voyage","Ensuite, nous avons vu la Sagrada Familia conçue par Gaudí","Puis nous nous sommes promenés dans le quartier gothique","Finalement, nous avons mangé une paella au bord de la mer"]'),
('frances', 'eso', '{2}', '["Hier soir, j''ai fini tous mes devoirs très tard","D''abord, j''ai fait les exercices de mathématiques les plus difficiles","Ensuite, j''ai étudié la leçon d''histoire pour l''examen","Puis j''ai rédigé une rédaction en français sur les vacances","Finalement, je suis allé me coucher épuisé mais satisfait"]'),
('frances', 'eso', '{2}', '["Pour devenir bon en français, j''ai suivi plusieurs étapes","D''abord, j''ai appris le vocabulaire de base avec des fiches","Ensuite, j''ai lu des livres simples adaptés''à mon niveau","Puis j''ai regardé des films français avec les sous-titres","Finalement, j''ai fait un séjour linguistique en France"]'),
('frances', 'eso', '{2}', '["Pour mon anniversaire, mes parents ont organisé une grande fête","Ils ont invité tous mes amis et mes cousins préférés","Ensuite, ma mère a préparé un gâteau énorme au chocolat","Puis tout le monde a chanté joyeux anniversaire en choeur","Finalement, j''ai ouvert mes cadeaux devant tous les invités"]'),
('frances', 'eso', '{2}', '["L''année dernière, j''ai participé à un concours de dessin","J''ai d''abord choisi le thème et préparé mon idée","Ensuite, j''ai dessiné pendant plusieurs heures avec concentration","Puis j''ai envoyé mon dessin au jury du concours","Finalement, j''ai gagné le deuxième prix avec beaucoup de fierté"]'),
('frances', 'eso', '{2}', '["Pour cuisiner des crêpes, j''ai d''abord préparé la pâte","J''ai mélangé la farine, les oeufs, le lait et le sel","Ensuite, j''ai laissé reposer la pâte pendant trente minutes","Puis j''ai fait chauffer une poêle avec un peu de beurre","Finalement, j''ai versé la pâte et fait cuire les crêpes"]'),
('frances', 'eso', '{2}', '["Le week-end dernier, nous sommes allés camper en forêt","Nous avons installé notre tente dans une belle clairière","Ensuite, nous avons fait un feu pour préparer le dîner","Puis nous avons observé les étoiles avant de dormir","Finalement, nous sommes rentrés dimanche soir après cette aventure"]'),
('frances', 'eso', '{2}', '["Ce matin, j''ai eu un examen important de mathématiques","Je me suis réveillé tôt pour réviser une dernière fois","Ensuite, je suis arrivé en avance à l''école","Puis j''ai fait l''examen avec beaucoup de concentration","Finalement, je suis sorti de la classe soulagé et fatigué"]'),
('frances', 'eso', '{2}', '["Hier, mon chat a disparu pendant plusieurs heures","J''ai cherché partout dans la maison sans le trouver","Ensuite, je suis sorti dans le jardin pour l''appeler","Puis mon voisin m''a dit l''avoir vu dans son garage","Finalement, mon chat est rentré fatigué mais en bonne santé"]'),
('frances', 'eso', '{2}', '["Pour apprendre à conduire un vélo, j''ai commencé jeune","Mon père m''a d''abord mis des petites roues de sécurité","Ensuite, j''ai pratiqué dans le jardin pendant plusieurs semaines","Puis mon père a enlevé les petites roues un jour","Finalement, j''ai pu rouler seul sans tomber"]'),
('frances', 'eso', '{2}', '["Le mois dernier, nous avons organisé un pique-nique en famille","Nous avons préparé des sandwichs et une grande salade","Ensuite, nous avons pris la voiture pour aller à la campagne","Puis nous avons installé la nappe sous un grand arbre","Finalement, nous avons passé un après-midi très''agréable"]'),
('frances', 'eso', '{2}', '["Pour préparer un croque-monsieur, j''ai besoin de pain de mie","J''ai d''abord mis du jambon sur une tranche de pain","Ensuite, j''ai ajouté du fromage râpé par-dessus","Puis j''ai mis une autre tranche de pain au-dessus","Finalement, j''ai fait griller le tout dans le four"]'),
('frances', 'eso', '{2}', '["L''hiver passé, je suis allé skier dans les Alpes","Nous avons loué le matériel au bas des pistes","Ensuite, j''ai pris des cours avec un moniteur expérimenté","Puis j''ai descendu ma première piste bleue sans tomber","Finalement, je suis devenu assez bon à la fin du séjour"]'),
('frances', 'eso', '{2}', '["Hier après-midi, j''ai rangé ma chambre qui était très désordre","D''abord, j''ai ramassé tous les vêtements par terre","Ensuite, j''ai fait mon lit et plié mes affaires","Puis j''ai passé l''aspirateur sur tout le sol","Finalement, ma chambre était propre et bien rangée"]'),
('frances', 'eso', '{2}', '["Pour fêter Noël, notre famille suit toujours les mêmes traditions","Nous avons décoré le sapin le premier dimanche de décembre","Ensuite, nous avons écrit nos lettres au Père Noël","Puis nous avons préparé un grand repas familial le vingt-quatre","Finalement, nous avons ouvert les cadeaux à minuit"]'),
('frances', 'eso', '{2}', '["Pour préparer une soupe de légumes, j''ai épluché les carottes","Ensuite, j''ai coupé les pommes de terre en petits cubes","Puis j''ai fait revenir un oignon dans une casserole","Après, j''ai ajouté tous les légumes avec de l''eau","Finalement, j''ai laissé cuire la soupe pendant quarante minutes"]'),
('frances', 'eso', '{2}', '["Samedi dernier, nous sommes allés''à la plage en famille","Nous avons mis nos maillots de bain et nos lunettes de soleil","Ensuite, nous avons nagé dans la mer pendant longtemps","Puis nous avons joué au volley sur le sable","Finalement, nous avons mangé une glace avant de rentrer"]'),
('frances', 'eso', '{2}', '["La semaine dernière, j''ai visité mon grand-père à la campagne","Il m''a montré son potager plein de légumes frais","Ensuite, nous avons cueilli des tomates et des courgettes","Puis il m''a appris à préparer une ratatouille","Finalement, nous avons mangé le plat ensemble au déjeuner"]'),
('frances', 'eso', '{2}', '["Pour passer mon permis de vélo, j''ai étudié le code","D''abord, j''ai appris tous les panneaux de signalisation","Ensuite, j''ai passé l''examen théorique à l''école","Puis j''ai fait l''épreuve pratique dans la cour","Finalement, j''ai obtenu mon permis avec une bonne note"]'),
('frances', 'eso', '{2}', '["Hier, j''ai aidé ma grand-mère à préparer des confitures","Nous avons d''abord lavé les fraises fraîches du jardin","Ensuite, nous avons coupé les fruits en petits morceaux","Puis nous avons ajouté du sucre et fait cuire lentement","Finalement, nous avons mis les confitures dans des pots"]'),
('frances', 'eso', '{2}', '["Le mois dernier, j''ai acheté un nouveau téléphone portable","Je suis d''abord allé dans plusieurs magasins pour comparer","Ensuite, j''ai choisi le modèle qui me plaisait le plus","Puis j''ai payé avec l''argent que j''avais économisé","Finalement, j''ai configuré mon nouveau téléphone à la maison"]'),
('frances', 'eso', '{2}', '["Pour organiser mon voyage, j''ai planifié chaque détail à l''avance","J''ai d''abord choisi ma destination et la durée du séjour","Ensuite, j''ai réservé les billets de train et l''hôtel","Puis j''ai fait une liste des activités''à faire sur place","Finalement, j''ai préparé ma valise avec tout le nécessaire"]'),
('frances', 'eso', '{2}', '["Dimanche dernier, nous avons fait du vélo en famille","Nous avons chargé les vélos dans la voiture très tôt","Ensuite, nous avons roulé le long d''une jolie rivière","Puis nous avons pique-niqué près d''un vieux moulin","Finalement, nous sommes rentrés''avec beaucoup de belles photos"]'),
('frances', 'eso', '{2}', '["Pour préparer un sandwich parfait, j''ai pris deux tranches de pain","Ensuite, j''ai mis du beurre sur chaque tranche","Puis j''ai ajouté du jambon, du fromage et de la salade","Après, j''ai fermé le sandwich et l''ai coupé en deux","Finalement, j''ai savouré mon sandwich avec un verre de jus"]'),
('frances', 'eso', '{2}', '["L''année passée, j''ai appris à jouer de la guitare","Mon professeur m''a d''abord montré comment tenir l''instrument","Ensuite, j''ai appris les premiers accords de base","Puis j''ai pratiqué tous les jours pour améliorer ma technique","Finalement, j''ai joué ma première chanson entière sans erreur"]'),
('frances', 'eso', '{2}', '["Hier soir, mes parents m''ont emmené au théâtre","Nous sommes arrivés vingt minutes avant le début du spectacle","Ensuite, nous avons trouvé nos places dans la salle","Puis les lumières se sont éteintes et la pièce a commencé","Finalement, nous avons applaudi les acteurs à la fin"]'),
('frances', 'eso', '{2}', '["Pour préparer un pain perdu, j''ai besoin de pain rassis","J''ai d''abord battu les oeufs avec du lait et du sucre","Ensuite, j''ai trempé les tranches de pain dans le mélange","Puis j''ai fait fondre du beurre dans une poêle chaude","Finalement, j''ai fait cuire les tranches des deux côtés"]'),
('frances', 'eso', '{2}', '["L''été dernier, j''ai travaillé comme moniteur dans une colonie","J''ai d''abord suivi une formation de trois jours","Ensuite, j''ai accueilli les enfants le premier jour","Puis j''ai organisé des activités sportives et artistiques","Finalement, j''ai passé trois semaines merveilleuses avec eux"]'),
('frances', 'eso', '{2}', '["Hier, j''ai perdu mes clés dans la rue","J''ai d''abord cherché partout dans mon sac à dos","Ensuite, j''ai refait le chemin de l''école à la maison","Puis j''ai demandé aux commerçants s''ils les avaient vues","Finalement, j''ai retrouvé mes clés devant la boulangerie"]'),
('frances', 'eso', '{2}', '["Pour préparer une omelette aux champignons, j''ai nettoyé les champignons","Ensuite, je les ai fait cuire dans une poêle avec du beurre","Puis j''ai battu trois oeufs dans un grand bol","Après, j''ai versé les oeufs sur les champignons","Finalement, j''ai plié l''omelette et l''ai servie chaude"]'),
('frances', 'eso', '{2}', '["La semaine dernière, j''ai eu un petit accident de vélo","Je roulais trop vite sur une route mouillée","Ensuite, j''ai dérapé et suis tombé par terre","Puis j''ai senti une douleur au genou gauche","Finalement, mes parents m''ont emmené chez le médecin"]'),
('frances', 'eso', '{2}', '["Pour ma première expérience à l''étranger, je suis allé en Angleterre","J''ai pris l''avion depuis Madrid jusqu''à Londres","Ensuite, j''ai été accueilli par une famille anglaise","Puis j''ai passé deux semaines à apprendre l''anglais","Finalement, je suis rentré chez moi avec beaucoup de progrès"]'),
('frances', 'eso', '{2}', '["Samedi, nous avons organisé un grand repas pour nos voisins","Ma mère a préparé une paella pour dix personnes","Ensuite, nous avons mis la table dans le jardin","Puis les voisins sont arrivés''avec du vin et des desserts","Finalement, nous avons mangé et ri jusqu''à la nuit"]'),
('frances', 'eso', '{2}', '["Pour créer un herbier, j''ai cueilli différentes plantes","Je les ai d''abord placées entre deux feuilles de papier","Ensuite, j''ai mis des livres lourds dessus pour les presser","Puis j''ai attendu plusieurs semaines pour qu''elles sèchent","Finalement, j''ai collé chaque plante dans un cahier spécial"]'),
('frances', 'eso', '{2}', '["Hier, je suis allé voir un concert avec mes amis","Nous avons acheté les billets en ligne il y a un mois","Ensuite, nous sommes arrivés tôt devant la salle de concert","Puis nous avons attendu dans la file pendant une heure","Finalement, nous avons profité du concert jusqu''à minuit"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'eso', '{3}', '["Quand j''étais petit, je vivais à la campagne avec mes grands-parents","Chaque matin, je me réveillais avec le chant des oiseaux","Je passais mes journées à jouer dehors avec mes cousins","Le soir, ma grand-mère me racontait de belles histoires","Ces souvenirs restent aujourd''hui parmi les plus précieux de ma vie"]'),
('frances', 'eso', '{3}', '["Pour protéger la planète, j''ai d''abord changé mes habitudes quotidiennes","Ensuite, j''ai commencé à trier les déchets à la maison","Puis j''ai remplacé la voiture par le vélo pour les trajets courts","Après, j''ai appris à économiser l''eau et l''électricité","Finalement, j''ai convaincu ma famille de faire la même chose"]'),
('frances', 'eso', '{3}', '["Autrefois, les paysans travaillaient la terre sans machines modernes","Ils se levaient avant le lever du soleil chaque matin","Ils labouraient les champs avec des boeufs et des charrues","Puis ils semaient les graines à la main avec patience","Finalement, ils récoltaient les fruits de leur travail en été"]'),
('frances', 'eso', '{3}', '["Pour lutter contre le changement climatique, les gouvernements ont pris des mesures","Ils ont d''abord signé des accords internationaux importants","Ensuite, ils ont promu les énergies renouvelables comme le solaire","Puis ils ont taxé les industries les plus polluantes","Finalement, ils ont encouragé le transport public dans les villes"]'),
('frances', 'eso', '{3}', '["Quand j''avais dix ans, je passais mes étés chez mon oncle","Il habitait dans un petit village au bord de la mer","Nous allions pêcher tous les jours avec son bateau","Le soir, nous mangions le poisson frais que nous avions attrapé","Ces vacances étaient toujours un moment magique pour moi"]'),
('frances', 'eso', '{3}', '["Pour préparer ma visite à Paris, j''ai étudié l''histoire de la ville","J''ai lu des livres sur les monuments les plus importants","Ensuite, j''ai planifié un itinéraire pour voir le maximum","Puis j''ai acheté un guide touristique et une carte détaillée","Finalement, mon voyage a été une expérience culturelle inoubliable"]'),
('frances', 'eso', '{3}', '["Il était une fois une princesse qui vivait dans un grand château","Elle était très belle mais aussi très seule dans ses appartements","Un jour, un jeune prince est arrivé au royaume pour la rencontrer","Ils sont tombés''amoureux dès leur première rencontre dans le jardin","Finalement, ils se sont mariés''et ont vécu heureux ensemble"]'),
('frances', 'eso', '{3}', '["Pour réduire la pollution plastique, les écoles organisent des campagnes","Elles sensibilisent d''abord les élèves aux dangers du plastique","Ensuite, elles remplacent les bouteilles jetables par des gourdes","Puis elles installent des points de recyclage dans les couloirs","Finalement, les élèves deviennent des ambassadeurs de l''environnement"]'),
('frances', 'eso', '{3}', '["Dans mon enfance, ma grand-mère me racontait des histoires de guerre","Elle avait vécu des moments très difficiles pendant son adolescence","Sa famille devait se cacher dans une cave pour éviter les bombes","Elle partageait un peu de pain avec ses frères et soeurs","Ces récits m''ont appris l''importance de la paix"]'),
('frances', 'eso', '{3}', '["Pour organiser une exposition à l''école, nous avons choisi le thème","Nous avons ensuite cherché des informations dans la bibliothèque","Puis nous avons préparé des panneaux avec des photos et textes","Après, nous avons installé les panneaux dans la salle polyvalente","Finalement, nous avons présenté notre travail aux autres classes"]'),
('frances', 'eso', '{3}', '["Au Moyen Âge, les chevaliers suivaient un code d''honneur très strict","Ils s''entraînaient au combat dès leur plus jeune âge","Ils devaient protéger les faibles et respecter les femmes","Ils participaient à des tournois pour démontrer leur bravoure","Finalement, ils étaient récompensés par le roi pour leurs exploits"]'),
('frances', 'eso', '{3}', '["Pour construire un panneau solaire, on assemble plusieurs cellules photovoltaïques","Ces cellules captent la lumière du soleil pendant la journée","L''énergie lumineuse est transformée en électricité par les cellules","Un onduleur convertit ensuite le courant continu en alternatif","Finalement, l''électricité produite alimente les appareils de la maison"]'),
('frances', 'eso', '{3}', '["Quand je vivais dans mon ancien quartier, je connaissais tous mes voisins","Chaque matin, je saluais le boulanger en achetant mon pain","Je jouais souvent dans le parc avec les enfants du quartier","Le dimanche, nous organisions des repas partagés''entre voisins","Aujourd''hui encore, je repense avec nostalgie à ces beaux moments"]'),
('frances', 'eso', '{3}', '["La Révolution française a commencé avec la prise de la Bastille","Les Parisiens en colère ont attaqué la prison le quatorze juillet","Ensuite, l''Assemblée nationale a aboli les privilèges féodaux","Puis la Déclaration des droits de l''homme a été rédigée","Finalement, la monarchie absolue a disparu de la France"]'),
('frances', 'eso', '{3}', '["Pour sauver les océans de la pollution, plusieurs actions sont nécessaires","Il faut d''abord réduire notre consommation de plastique quotidienne","Ensuite, il faut participer au nettoyage des plages et rivières","Puis il faut soutenir les associations qui protègent la vie marine","Finalement, il faut informer les autres des risques de la pollution"]'),
('frances', 'eso', '{3}', '["Autrefois, les enfants allaient à l''école dans des conditions difficiles","Ils marchaient souvent plusieurs kilomètres pour arriver en classe","Les salles étaient froides et mal éclairées par de petites fenêtres","Les élèves écrivaient sur des ardoises avec des craies blanches","Aujourd''hui, l''école a beaucoup changé grâce aux progrès techniques"]'),
('frances', 'eso', '{3}', '["Pour faire un documentaire sur les animaux, j''ai commencé par chercher","J''ai d''abord choisi un animal qui m''intéressait beaucoup","Ensuite, j''ai lu plusieurs livres pour connaître ses habitudes","Puis je suis allé au zoo pour le filmer de près","Finalement, j''ai monté toutes les images en un beau film"]'),
('frances', 'eso', '{3}', '["Les impressionnistes ont révolutionné la peinture à la fin du dix-neuvième siècle","Ils peignaient en plein air pour capter la vraie lumière","Ils utilisaient des couleurs vives et des coups de pinceau rapides","Leurs tableaux montraient des scènes de la vie quotidienne","Aujourd''hui, leurs oeuvres sont parmi les plus célèbres du monde"]'),
('frances', 'eso', '{3}', '["Pour créer un jardin écologique, il faut d''abord choisir les plantes locales","Ensuite, on prépare la terre avec du compost naturel","Puis on plante en respectant les saisons et les distances","Après, on installe un système d''arrosage économique","Finalement, on observe le jardin grandir sans utiliser de pesticides"]'),
('frances', 'eso', '{3}', '["Quand ma mère était jeune, elle rêvait de devenir médecin","Elle étudiait très dur tous les soirs après l''école","Ses parents n''avaient pas beaucoup d''argent pour payer l''université","Elle a obtenu une bourse grâce à ses excellents résultats","Finalement, elle a réalisé son rêve et sauve des vies aujourd''hui"]'),
('frances', 'eso', '{3}', '["Pour rédiger un article de journal, le journaliste enquête sur le sujet","Il interroge plusieurs témoins pour avoir différents points de vue","Ensuite, il vérifie soigneusement les informations qu''il a obtenues","Puis il rédige son article avec un style clair et précis","Finalement, il envoie son article au rédacteur en chef"]'),
('frances', 'eso', '{3}', '["Les premiers hommes vivaient dans des grottes pour se protéger","Ils chassaient les animaux sauvages avec des armes primitives","Ils faisaient du feu pour cuire la viande et se réchauffer","Ils peignaient les murs de leurs grottes avec des dessins","Ces peintures nous renseignent sur leur mode de vie ancien"]'),
('frances', 'eso', '{3}', '["Pour planter un arbre, il faut choisir le bon emplacement","Ensuite, on creuse un trou assez grand et profond","Puis on place l''arbre avec ses racines dans le trou","Après, on remplit le trou avec de la terre fertile","Finalement, on arrose abondamment pour aider l''arbre à s''enraciner"]'),
('frances', 'eso', '{3}', '["Quand j''étais enfant, ma famille partait toujours à la montagne","Nous passions des journées entières à randonner dans les sentiers","Mon père m''apprenait à reconnaître les différentes plantes sauvages","Nous pique-niquions près des lacs cristallins en admirant le paysage","Ces expériences ont développé mon amour pour la nature"]'),
('frances', 'eso', '{3}', '["Pour fabriquer du pain traditionnel, le boulanger mélange la farine et l''eau","Il ajoute ensuite le sel et la levure naturelle","Puis il pétrit la pâte pendant longtemps avec ses mains","Après, il laisse reposer la pâte pour qu''elle lève","Finalement, il cuit le pain dans un four à bois"]'),
('frances', 'eso', '{3}', '["Victor Hugo était un écrivain français très célèbre au dix-neuvième siècle","Il a écrit des romans importants comme Les Misérables","Il défendait aussi les causes sociales à travers ses oeuvres","Il a vécu en exil pendant près de vingt ans","Aujourd''hui, son nom est associé à la littérature universelle"]'),
('frances', 'eso', '{3}', '["Pour économiser l''énergie chez soi, on peut prendre plusieurs mesures simples","Il faut d''abord éteindre les appareils qu''on n''utilise pas","Ensuite, il faut baisser le chauffage de quelques degrés","Puis on peut remplacer les ampoules classiques par des LED","Finalement, on peut isoler correctement les fenêtres et les murs"]'),
('frances', 'eso', '{3}', '["Au temps de mes grands-parents, la vie était très différente d''aujourd''hui","Il n''y avait ni téléphone portable ni internet dans les maisons","Les gens se rencontraient face à face pour discuter ensemble","Les enfants jouaient dehors avec des jeux simples et créatifs","Cette époque semble bien éloignée de notre monde connecté actuel"]'),
('frances', 'eso', '{3}', '["Pour préparer une exposition scientifique, nous avons formé un groupe","Nous avons d''abord choisi un sujet lié à l''écologie","Ensuite, nous avons cherché des informations dans des livres spécialisés","Puis nous avons réalisé des expériences pour illustrer nos idées","Finalement, nous avons présenté nos découvertes devant toute l''école"]'),
('frances', 'eso', '{3}', '["Les cathédrales gothiques ont été construites pendant le Moyen Âge","Les architectes utilisaient de nouvelles techniques comme les arcs-boutants","Les ouvriers taillaient les pierres avec beaucoup de précision","Les vitraux colorés racontaient des histoires religieuses aux fidèles","Ces monuments représentent des chefs-d''oeuvre de l''art gothique"]'),
('frances', 'eso', '{3}', '["Pour organiser un débat en classe, nous avons choisi un thème actuel","Nous avons d''abord fait des recherches approfondies sur le sujet","Ensuite, nous avons formé deux équipes avec des opinions différentes","Puis nous avons préparé nos arguments avec soin","Finalement, le débat a été très''enrichissant pour tout le monde"]'),
('frances', 'eso', '{3}', '["Dans le passé, les femmes n''avaient pas les mêmes droits que les hommes","Elles ne pouvaient pas voter lors des élections politiques","Elles n''avaient pas accès''à certaines professions importantes","Grâce à de nombreuses luttes, les choses ont beaucoup changé","Aujourd''hui, l''égalité progresse mais il reste encore du travail"]'),
('frances', 'eso', '{3}', '["Pour adopter un animal de compagnie, il faut bien réfléchir","On doit d''abord choisir un animal adapté à notre mode de vie","Ensuite, on doit préparer tout le matériel nécessaire à la maison","Puis on se rend au refuge pour choisir son nouveau compagnon","Finalement, on prend soin de lui chaque jour avec amour"]'),
('frances', 'eso', '{3}', '["Quand ma mère allait à l''école, les ordinateurs n''existaient pas","Elle écrivait ses devoirs à la main dans des cahiers","Elle cherchait ses informations dans des encyclopédies en papier","Les professeurs utilisaient des tableaux noirs et des craies","Cette époque semble très lointaine par rapport à notre réalité numérique"]'),
('frances', 'eso', '{3}', '["Pour traiter les déchets recyclables, les camions les ramassent d''abord","Ensuite, ils transportent les matériaux vers un centre de tri","Puis les travailleurs séparent le plastique, le papier et le verre","Après, chaque matériau est transformé en nouvelles matières premières","Finalement, ces matières servent à fabriquer de nouveaux produits"]'),
('frances', 'eso', '{3}', '["Napoléon Bonaparte est devenu empereur des Français en mille huit cent quatre","Il a mené de nombreuses campagnes militaires à travers l''Europe","Il a créé des institutions modernes comme le Code civil","Son règne a pris fin avec la défaite de Waterloo","Il reste une figure controversée mais importante de l''histoire"]'),
('frances', 'eso', '{3}', '["Pour réduire ma consommation d''eau, j''ai fait plusieurs changements","Je prends maintenant des douches rapides au lieu des bains","Ensuite, je ferme le robinet quand je me brosse les dents","Puis j''ai installé un récupérateur d''eau de pluie","Finalement, ma facture d''eau a beaucoup diminué"]'),
('frances', 'eso', '{3}', '["Dans les années soixante, les jeunes voulaient changer la société","Ils écoutaient une nouvelle musique comme le rock and roll","Ils portaient des vêtements colorés''et originaux","Ils participaient à des manifestations pour la paix et la liberté","Cette génération a marqué l''histoire culturelle du vingtième siècle"]'),
('frances', 'eso', '{3}', '["Pour préparer un voyage culturel, j''ai cherché des informations intéressantes","J''ai d''abord choisi les musées les plus importants à visiter","Ensuite, j''ai lu des livres sur l''histoire locale","Puis j''ai noté les spécialités culinaires à découvrir","Finalement, mon voyage a été beaucoup plus enrichissant grâce à cette préparation"]'),
('frances', 'eso', '{3}', '["Marie Curie était une scientifique extraordinaire née en Pologne","Elle a étudié à Paris dans des conditions difficiles","Elle a découvert deux nouveaux éléments chimiques avec son mari","Elle a reçu deux prix Nobel pour ses recherches révolutionnaires","Elle reste un modèle pour les femmes scientifiques du monde entier"]'),
('frances', 'eso', '{3}', '["Pour diminuer la pollution dans les villes, plusieurs solutions existent","On peut d''abord développer les transports publics écologiques","Ensuite, on peut créer davantage de pistes cyclables sécurisées","Puis on peut planter des arbres dans les rues et places","Finalement, on peut limiter la circulation des voitures polluantes"]'),
('frances', 'eso', '{3}', '["Quand j''étais à l''école primaire, j''adorais les cours de sciences","Le professeur nous faisait faire des expériences très''intéressantes","Nous observions les plantes pousser dans le jardin de l''école","Nous étudiions aussi les différents animaux et leurs habitats","Ces souvenirs ont nourri ma passion actuelle pour la biologie"]'),
('frances', 'eso', '{3}', '["La littérature française est riche et variée depuis des siècles","Au Moyen Âge, les troubadours composaient des poèmes d''amour","À la Renaissance, les écrivains ont redécouvert les classiques grecs","Au siècle des Lumières, les philosophes défendaient la raison","Aujourd''hui, de nombreux auteurs continuent cette belle tradition littéraire"]'),
('frances', 'eso', '{3}', '["Pour créer une bande dessinée, j''ai commencé par imaginer l''histoire","J''ai ensuite dessiné les personnages principaux avec soin","Puis j''ai divisé le récit en cases et en pages","Après, j''ai ajouté les dialogues dans des bulles","Finalement, j''ai colorié chaque case avec des crayons de couleur"]'),
('frances', 'eso', '{3}', '["Pendant la Seconde Guerre mondiale, beaucoup de familles souffraient","Elles devaient se cacher pour échapper aux bombardements constants","Les enfants ne pouvaient pas aller à l''école normalement","Les gens partageaient le peu de nourriture qu''ils avaient","Cette période sombre a marqué des générations entières"]'),
('frances', 'eso', '{3}', '["Pour visiter un musée intelligemment, il faut bien se préparer","On consulte d''abord le plan du musée avant d''entrer","Ensuite, on sélectionne les oeuvres les plus importantes à voir","Puis on prend le temps d''admirer chaque oeuvre choisie","Finalement, on achète un petit souvenir dans la boutique"]'),
('frances', 'eso', '{3}', '["Autrefois, les artisans apprenaient leur métier pendant de longues années","Ils commençaient comme apprentis chez un maître expérimenté","Ils observaient attentivement chaque geste et technique du maître","Ils pratiquaient ensuite sous sa supervision bienveillante","Finalement, ils devenaient eux-mêmes des maîtres de leur art"]'),
('frances', 'eso', '{3}', '["Pour protéger les forêts menacées, plusieurs actions sont essentielles","Il faut d''abord lutter contre la déforestation massive","Ensuite, il faut replanter des arbres dans les zones dégradées","Puis il faut créer des zones protégées pour préserver la biodiversité","Finalement, il faut éduquer les nouvelles générations au respect de la nature"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'eso', '{4}', '["Il est important que nous comprenions les enjeux du changement climatique","Les scientifiques ont d''abord alerté la communauté internationale dès les années soixante-dix","Ensuite, plusieurs accords internationaux ont été signés pour limiter les émissions","Puis les entreprises ont commencé à investir dans les énergies propres","Finalement, chaque citoyen doit faire sa part pour préserver la planète"]'),
('frances', 'eso', '{4}', '["Pour que la démocratie fonctionne, il faut que les citoyens participent activement","Ils doivent d''abord s''informer sur les enjeux politiques de leur pays","Ensuite, ils participent aux débats publics avec respect et argumentation","Puis ils votent consciencieusement lors des différentes élections","Finalement, ils exercent un contrôle citoyen sur les décisions prises"]'),
('frances', 'eso', '{4}', '["Albert Camus a écrit L''Étranger au début de la Seconde Guerre mondiale","Ce roman raconte l''histoire de Meursault, un homme indifférent au monde","Le protagoniste commet un meurtre absurde sur une plage algérienne","Il est ensuite jugé et condamné pour son comportement étrange","Cette oeuvre est devenue un classique de la littérature française moderne"]'),
('frances', 'eso', '{4}', '["Bien que la société ait beaucoup évolué, les inégalités persistent encore","Les différences entre riches et pauvres continuent de s''accroître","Les femmes gagnent toujours moins que les hommes pour le même travail","Les minorités rencontrent encore des discriminations dans plusieurs domaines","Il est essentiel que nous luttions contre ces injustices persistantes"]'),
('frances', 'eso', '{4}', '["Pour rédiger une dissertation littéraire, il faut d''abord analyser le sujet","Ensuite, on recherche des arguments et des exemples pertinents dans les oeuvres","Puis on construit un plan détaillé avec introduction et conclusion","Après, on rédige chaque partie en respectant la structure argumentative","Finalement, on relit soigneusement pour corriger les fautes éventuelles"]'),
('frances', 'eso', '{4}', '["Il faudrait que les gouvernements investissent davantage dans l''éducation publique","Les enseignants ont besoin de ressources adéquates pour leur travail","Les élèves méritent des infrastructures modernes et confortables","Les parents doivent avoir confiance dans le système éducatif","Finalement, l''éducation est la clé du développement d''une société juste"]'),
('frances', 'eso', '{4}', '["Molière était un dramaturge français du dix-septième siècle très célèbre","Il écrivait des comédies qui critiquaient les défauts de son époque","Ses pièces comme Tartuffe ont provoqué des scandales à la cour","Il jouait lui-même dans ses pièces devant le roi Louis quatorze","Aujourd''hui, ses oeuvres continuent d''être jouées dans le monde entier"]'),
('frances', 'eso', '{4}', '["Pour que les jeunes s''engagent dans la société, il faut les écouter","Les adultes doivent prendre au sérieux leurs opinions et préoccupations","Ensuite, il faut leur donner des espaces de dialogue véritable","Puis on peut les impliquer dans les décisions qui les concernent","Finalement, ils deviennent des acteurs responsables du changement social"]'),
('frances', 'eso', '{4}', '["La Révolution industrielle a transformé profondément les sociétés''européennes","Elle a d''abord commencé en Angleterre avec les machines à vapeur","Ensuite, les fabriques ont remplacé le travail artisanal traditionnel","Puis les gens sont partis des campagnes pour travailler dans les villes","Finalement, ces changements ont créé une nouvelle classe ouvrière importante"]'),
('frances', 'eso', '{4}', '["Il est nécessaire que nous préservions notre patrimoine culturel commun","Les monuments historiques témoignent de notre riche passé collectif","Les traditions populaires transmettent des valeurs importantes aux nouvelles générations","Les langues régionales représentent une richesse culturelle à protéger","Finalement, ce patrimoine fait partie intégrante de notre identité"]'),
('frances', 'eso', '{4}', '["Pour organiser un voyage solidaire dans un pays en développement, il faut préparer","Nous avons d''abord contacté une association humanitaire sérieuse et reconnue","Ensuite, nous avons suivi une formation sur le contexte local","Puis nous avons collecté des fonds grâce à des événements caritatifs","Finalement, nous avons passé un mois à aider une école rurale"]'),
('frances', 'eso', '{4}', '["Simone de Beauvoir a écrit Le Deuxième Sexe en mille neuf cent quarante-neuf","Ce livre analyse la condition des femmes dans la société occidentale","Elle y défend l''idée célèbre qu''on ne naît pas femme, on le devient","L''ouvrage a inspiré les mouvements féministes du vingtième siècle","Aujourd''hui, ses idées restent d''une actualité brûlante pour l''égalité"]'),
('frances', 'eso', '{4}', '["Bien que la technologie facilite notre vie quotidienne, elle a aussi des inconvénients","Elle peut créer une dépendance excessive chez les jeunes utilisateurs","Elle réduit parfois les interactions sociales réelles entre les personnes","Elle pose également des problèmes importants de protection de la vie privée","Finalement, il faut l''utiliser avec sagesse et modération"]'),
('frances', 'eso', '{4}', '["Pour devenir un citoyen responsable, plusieurs compétences sont essentielles","Il faut d''abord apprendre à penser de manière critique et autonome","Ensuite, il faut développer son empathie envers les autres personnes","Puis il faut s''informer régulièrement sur l''actualité nationale et internationale","Finalement, il faut s''engager concrètement pour les causes qui nous tiennent à coeur"]'),
('frances', 'eso', '{4}', '["Le Petit Prince est un conte philosophique écrit par Saint-Exupéry","L''auteur raconte l''histoire d''un pilote perdu dans le désert du Sahara","Il y rencontre un petit prince venu d''une planète lointaine","Le prince lui raconte ses voyages et ses rencontres étranges","Cette oeuvre est traduite en plus de trois cents langues dans le monde"]'),
('frances', 'eso', '{4}', '["Il est dommage que tant de personnes souffrent de la faim dans le monde","Les causes principales sont les guerres et les changements climatiques","Les organisations humanitaires essaient d''apporter une aide d''urgence","Mais les solutions à long terme nécessitent des changements politiques","Finalement, chaque citoyen peut contribuer à cette lutte essentielle"]'),
('frances', 'eso', '{4}', '["Pour analyser un poème, on commence par identifier son genre littéraire","Ensuite, on étudie sa structure formelle comme les strophes et les rimes","Puis on analyse les figures de style utilisées par l''auteur","Après, on interprète le sens profond et les émotions exprimées","Finalement, on situe l''oeuvre dans son contexte historique et culturel"]'),
('frances', 'eso', '{4}', '["La mondialisation a rapproché les peuples mais crée aussi des tensions","Elle permet d''abord les échanges commerciaux entre tous les pays","Ensuite, elle facilite la diffusion des cultures et des idées","Puis elle provoque parfois la disparition des traditions locales","Finalement, il faut trouver un équilibre entre ouverture et préservation"]'),
('frances', 'eso', '{4}', '["Pour que l''intégration des immigrés réussisse, plusieurs conditions sont nécessaires","Il faut d''abord leur offrir des cours de langue gratuits et accessibles","Ensuite, il faut faciliter leur accès''à l''emploi et au logement","Puis il faut lutter contre toute forme de discrimination","Finalement, il faut favoriser les échanges interculturels dans les quartiers"]'),
('frances', 'eso', '{4}', '["Victor Hugo a écrit Les Misérables pendant son exil politique","Ce roman épique raconte l''histoire de Jean Valjean, un ancien bagnard","Le protagoniste cherche la rédemption tout au long de son existence","L''oeuvre dénonce aussi les injustices sociales du dix-neuvième siècle","Aujourd''hui, ce livre est considéré comme un chef-d''oeuvre universel"]'),
('frances', 'eso', '{4}', '["Il faut que nous respections la diversité culturelle dans notre société","Chaque culture apporte des richesses uniques à l''humanité entière","Les échanges interculturels favorisent la compréhension mutuelle entre les peuples","Le dialogue permet de dépasser les préjugés''et les stéréotypes","Finalement, la diversité est une force pour vivre ensemble harmonieusement"]'),
('frances', 'eso', '{4}', '["Pour préparer un exposé sur un auteur, il faut procéder méthodiquement","On commence par rechercher des informations sur sa biographie détaillée","Ensuite, on lit plusieurs de ses oeuvres les plus représentatives","Puis on analyse son style d''écriture et ses thèmes préférés","Finalement, on organise toutes ces informations en une présentation cohérente"]'),
('frances', 'eso', '{4}', '["La presse libre joue un rôle essentiel dans toute démocratie moderne","Elle informe d''abord les citoyens sur l''actualité politique et sociale","Ensuite, elle enquête sur les abus de pouvoir et la corruption","Puis elle offre différentes perspectives sur les questions importantes","Finalement, elle permet aux citoyens de se forger leur propre opinion"]'),
('frances', 'eso', '{4}', '["Bien que l''art contemporain soit parfois difficile à comprendre, il mérite notre attention","Les artistes modernes remettent en question nos certitudes habituelles","Ils utilisent de nouveaux matériaux et techniques innovantes","Ils abordent souvent des thèmes sociaux et politiques importants","Finalement, leur travail nous aide à voir le monde autrement"]'),
('frances', 'eso', '{4}', '["Pour écrire une nouvelle littéraire, il faut d''abord imaginer un personnage","Ensuite, on crée une situation initiale qui éveille l''intérêt du lecteur","Puis on développe une intrigue avec des obstacles et des rebondissements","Après, on arrive au climax où tout se joue pour le héros","Finalement, on conclut avec une fin surprenante ou émouvante"]'),
('frances', 'eso', '{4}', '["Il est probable que l''intelligence artificielle transforme profondément nos sociétés","Elle aidera d''abord les médecins à diagnostiquer les maladies plus rapidement","Ensuite, elle automatisera de nombreuses tâches répétitives dans les entreprises","Puis elle pourra poser des questions éthiques complexes à résoudre","Finalement, nous devrons apprendre à coexister avec ces nouvelles technologies"]'),
('frances', 'eso', '{4}', '["Charles Baudelaire a publié Les Fleurs du mal en mille huit cent cinquante-sept","Ce recueil a provoqué un énorme scandale à son époque","Le poète y explorait les thèmes de la beauté et de la mort","Il a même été jugé pour outrage aux bonnes moeurs","Aujourd''hui, cette oeuvre est considérée comme fondamentale de la poésie moderne"]'),
('frances', 'eso', '{4}', '["Pour lutter contre le harcèlement scolaire, toute la communauté doit s''impliquer","Les professeurs doivent d''abord rester attentifs aux signes inquiétants","Ensuite, les élèves doivent oser dénoncer les comportements agressifs","Puis les parents doivent dialoguer ouvertement avec leurs enfants","Finalement, l''école doit mettre en place des protocoles clairs et efficaces"]'),
('frances', 'eso', '{4}', '["Le cinéma français est reconnu mondialement pour sa qualité artistique","La Nouvelle Vague des années cinquante a révolutionné le septième art","Des réalisateurs comme Truffaut ont apporté un regard neuf et original","Ils filmaient dans la rue avec des techniques novatrices","Aujourd''hui, le cinéma français continue d''innover et de surprendre"]'),
('frances', 'eso', '{4}', '["Il serait souhaitable que nous adoptions un mode de vie plus durable","Nous devrions consommer moins mais de meilleure qualité","Ensuite, nous pourrions privilégier les produits locaux et de saison","Puis nous réduirions nos déplacements en voiture au strict nécessaire","Finalement, nous préserverions les ressources pour les générations futures"]'),
('frances', 'eso', '{4}', '["Pour analyser un texte argumentatif, on identifie d''abord la thèse défendue","Ensuite, on repère les arguments principaux utilisés par l''auteur","Puis on étudie les exemples qui illustrent chaque argument","Après, on examine les connecteurs logiques qui structurent le raisonnement","Finalement, on évalue la force et la validité de l''argumentation"]'),
('frances', 'eso', '{4}', '["La question de l''identité est centrale dans la littérature française contemporaine","De nombreux écrivains explorent leurs origines multiples et complexes","Ils interrogent les notions de nation, de culture et d''appartenance","Leurs romans reflètent une société de plus en plus diverse","Ces oeuvres enrichissent notre compréhension du monde actuel"]'),
('frances', 'eso', '{4}', '["Pour créer une association étudiante, plusieurs étapes sont nécessaires","On réunit d''abord un groupe de personnes motivées par le même projet","Ensuite, on rédige les statuts qui définissent le fonctionnement","Puis on déclare officiellement l''association à la préfecture","Finalement, on organise des actions concrètes pour atteindre nos objectifs"]'),
('frances', 'eso', '{4}', '["Bien que la science ait fait d''énormes progrès, beaucoup reste à découvrir","Les chercheurs travaillent constamment pour percer les mystères de l''univers","Ils explorent les profondeurs des océans encore largement inconnues","Ils étudient aussi le fonctionnement complexe du cerveau humain","Finalement, chaque découverte ouvre la porte à de nouvelles questions"]'),
('frances', 'eso', '{4}', '["Marcel Proust a écrit son chef-d''oeuvre À la recherche du temps perdu","Ce roman monumental explore la mémoire et le passage du temps","Il commence par la fameuse scène de la madeleine trempée dans le thé","L''auteur a passé presque toute sa vie à écrire cette oeuvre","Aujourd''hui, son style unique influence encore de nombreux écrivains"]'),
('frances', 'eso', '{4}', '["Il est essentiel que nous protégions la liberté d''expression dans nos sociétés","Ce droit fondamental permet le débat démocratique et le progrès social","Il faut cependant qu''il soit exercé avec responsabilité et respect","Les limites doivent être clairement définies par la loi","Finalement, la liberté d''expression reste un pilier de nos démocraties"]'),
('frances', 'eso', '{4}', '["Pour organiser un événement culturel à l''école, on doit bien planifier","Le comité d''organisation choisit d''abord le thème et la date","Ensuite, il obtient les autorisations nécessaires auprès de la direction","Puis il répartit les tâches entre tous les membres du groupe","Finalement, l''événement se déroule avec succès devant tout le public"]'),
('frances', 'eso', '{4}', '["La philosophie des Lumières a profondément marqué l''histoire européenne","Voltaire et Rousseau défendaient la raison et les droits humains","Ils critiquaient l''absolutisme royal et les privilèges de l''Église","Leurs idées ont inspiré la Révolution française de mille sept cent quatre-vingt-neuf","Encore aujourd''hui, leurs principes guident nos démocraties modernes"]'),
('frances', 'eso', '{4}', '["Pour que l''écologie progresse, chaque citoyen doit agir à son niveau","Les petits gestes quotidiens peuvent avoir un grand impact cumulé","Ensuite, il faut soutenir les associations qui protègent l''environnement","Puis on peut sensibiliser son entourage aux enjeux écologiques","Finalement, le changement commence toujours par une prise de conscience"]'),
('frances', 'eso', '{4}', '["Jean-Paul Sartre a été une figure majeure de l''existentialisme français","Sa philosophie affirmait que l''existence précède l''essence humaine","Il a écrit des essais philosophiques mais aussi des romans célèbres","Il refusait les honneurs et défendait ses convictions politiques","Son oeuvre continue d''influencer la pensée contemporaine mondiale"]'),
('frances', 'eso', '{4}', '["Pour analyser la société actuelle, les sociologues étudient plusieurs aspects","Ils observent d''abord les transformations de la famille moderne","Ensuite, ils étudient l''évolution du travail et des loisirs","Puis ils analysent l''impact des nouvelles technologies sur nos relations","Finalement, ils proposent des théories pour comprendre ces changements"]'),
('frances', 'eso', '{4}', '["Il est regrettable que tant de conflits persistent encore dans le monde","Les causes sont souvent historiques, religieuses ou économiques","Les populations civiles en subissent toujours les conséquences les plus graves","Les organisations internationales tentent de médiatiser les différends","Finalement, la paix reste un objectif à construire chaque jour"]'),
('frances', 'eso', '{4}', '["Pour rédiger un essai, on commence par formuler clairement sa thèse","Ensuite, on rassemble les arguments et les exemples pertinents","Puis on organise le tout selon un plan logique et cohérent","Après, on rédige en soignant le style et la langue","Finalement, on révise le texte pour corriger les erreurs éventuelles"]'),
('frances', 'eso', '{4}', '["Le surréalisme est un mouvement artistique né au début du vingtième siècle","André Breton en a rédigé le manifeste en mille neuf cent vingt-quatre","Les surréalistes exploraient les rêves et l''inconscient humain","Ils utilisaient l''écriture automatique pour libérer leur créativité","Leurs oeuvres continuent de fasciner le public par leur étrangeté"]'),
('frances', 'eso', '{4}', '["Pour comprendre l''actualité, il ne suffit pas de lire un seul journal","Il faut consulter plusieurs sources d''information différentes","Ensuite, il faut comparer les points de vue présentés","Puis on vérifie les faits auprès de sources fiables","Finalement, on se forme une opinion personnelle éclairée et nuancée"]'),
('frances', 'eso', '{4}', '["Bien que les études soient exigeantes, elles ouvrent de nombreuses portes","Elles permettent d''abord d''acquérir des connaissances solides dans un domaine","Ensuite, elles développent l''esprit critique et l''autonomie intellectuelle","Puis elles offrent des opportunités professionnelles plus variées","Finalement, elles enrichissent notre compréhension du monde qui nous entoure"]'),
('frances', 'eso', '{4}', '["Pour que l''Europe se construise durablement, les États doivent coopérer","Ils partagent d''abord des valeurs communes comme la démocratie","Ensuite, ils coordonnent leurs politiques économiques et sociales","Puis ils défendent ensemble leurs intérêts sur la scène internationale","Finalement, l''Union européenne représente un modèle unique de coopération pacifique"]'),
('frances', 'eso', '{4}', '["Antoine de Saint-Exupéry était un aviateur et écrivain français passionné","Il a écrit plusieurs livres inspirés de ses expériences aériennes","Son oeuvre la plus célèbre reste évidemment Le Petit Prince","Il a disparu mystérieusement pendant une mission en mille neuf cent quarante-quatre","Aujourd''hui, son héritage littéraire continue d''émerveiller les lecteurs"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'eso', '{1}', '["Per a escriure correctament una paraula dubtosa, primer hem de pensar","Després, busquem la paraula al diccionari si no estem segurs","A continuació, identifiquem si porta accent o no segons les regles","Posteriorment, comprovem si és''aguda, plana o esdrúixola","Finalment, escrivim la paraula amb totes les normes ortogràfiques correctes"]'),
('valenciano', 'eso', '{1}', '["Els substantius són paraules que serveixen per a anomenar persones o coses","En primer lloc, poden ser comuns o propis segons el cas","En segon lloc, tenen gènere masculí o femení clarament diferenciat","A més, presenten nombre singular o plural segons la quantitat","Finalment, concorden sempre amb els articles i els adjectius que els acompanyen"]'),
('valenciano', 'eso', '{1}', '["Per a fer un bon resum d''un text, seguim diversos passos","Primer, llegim el text complet per entendre la idea general","Després, subratllem les idees principals de cada paràgraf amb llapis","A continuació, escrivim aquestes idees amb les nostres pròpies paraules","Finalment, revisem que el resum tinga sentit i siga coherent"]'),
('valenciano', 'eso', '{1}', '["Els verbs expressen accions, estats o processos que realitzen els subjectes","En primer lloc, es classifiquen en tres conjugacions diferents segons la terminació","En segon lloc, tenen diversos temps que indiquen quan passa l''acció","A més, presenten modes verbals com l''indicatiu o el subjuntiu","Finalment, són''el nucli del predicat en qualsevol oració completa"]'),
('valenciano', 'eso', '{1}', '["Un conte tradicional sempre comença amb una presentació dels personatges","A continuació, apareix un problema o conflicte que cal resoldre","Després, el protagonista viu diverses aventures buscant la solució","Posteriorment, arriba el moment culminant on tot es resol","Finalment, el conte acaba amb una lliçó moral per al lector"]'),
('valenciano', 'eso', '{1}', '["Les vocals tòniques són''aquelles que reben l''accent d''intensitat","En primer lloc, identifiquem la síl·laba forta de cada paraula","En segon lloc, comprovem si aquesta síl·laba porta accent gràfic","A més, recordem les regles d''accentuació per als casos dubtosos","Finalment, escrivim la paraula respectant sempre aquestes normes ortogràfiques"]'),
('valenciano', 'eso', '{1}', '["Per a analitzar morfològicament una paraula, comencem pel lexema","Després, identifiquem els possibles prefixos que apareixen davant del lexema","A continuació, busquem els sufixos que es troben darrere del lexema","Posteriorment, identifiquem les desinències de gènere, nombre o temps","Finalment, classifiquem la paraula segons la categoria gramatical corresponent"]'),
('valenciano', 'eso', '{1}', '["L''adjectiu és''una paraula que qualifica o determina el substantiu","En primer lloc, pot ser qualificatiu quan expressa una qualitat","En segon lloc, concorda amb el substantiu en gènere i nombre","A més, pot anar davant o darrere del substantiu al qual acompanya","Finalment, aporta informació descriptiva per a completar el significat"]'),
('valenciano', 'eso', '{1}', '["Per a aprendre una nova paraula, fem diverses activitats a classe","Primer, el professor ens explica el significat amb exemples clars","Després, escrivim la paraula diverses vegades al nostre quadern","A continuació, construïm''una oració utilitzant aquesta paraula nova","Finalment, la memoritzem practicant en contextos variats durant la setmana"]'),
('valenciano', 'eso', '{1}', '["Els signes de puntuació ajuden a entendre millor el significat del text","En primer lloc, el punt indica el final d''una oració completa","En segon lloc, la coma marca pauses breus dins d''una mateixa oració","A més, els punts suspensius expressen continuïtat o dubte del parlant","Finalment, els signes d''interrogació indiquen que hi ha una pregunta"]'),
('valenciano', 'eso', '{1}', '["Per a escriure una carta informal, primer saludem al destinatari","Després, expliquem el motiu de la carta a l''inici","A continuació, desenvolupem el contingut amb els detalls importants","Posteriorment, ens acomiadem de manera afectuosa del destinatari","Finalment, signem la carta amb el nostre nom o firma"]'),
('valenciano', 'eso', '{1}', '["Els pronoms personals substitueixen al nom dins d''una oració","En primer lloc, n''hi ha de primera, segona i tercera persona","En segon lloc, tenen formes diferents per al singular i el plural","A més, poden funcionar com a subjecte o com a complement","Finalment, ajuden a evitar repeticions innecessàries dins d''un text"]'),
('valenciano', 'eso', '{1}', '["Per a fer un dictat correctament, primer hem de prestar molta atenció","Després, escoltem la frase sencera abans de començar a escriure","A continuació, escrivim respectant les pauses marcades pel professor","Posteriorment, revisem el text buscant possibles errors ortogràfics","Finalment, corregim junts les faltes amb tota la classe"]'),
('valenciano', 'eso', '{1}', '["La síl·laba és''el conjunt de sons que pronunciem en un sol colp","En primer lloc, identifiquem totes les síl·labes que forma una paraula","En segon lloc, localitzem quina és la síl·laba tònica del mot","A més, classifiquem la paraula segons la posició d''aquesta síl·laba","Finalment, apliquem les regles d''accentuació segons el tipus de paraula"]'),
('valenciano', 'eso', '{1}', '["Els articles determinats acompanyen el substantiu al qual es refereixen","En primer lloc, concorden amb el substantiu en gènere i nombre","En segon lloc, les formes masculines són''el i els","A més, les formes femenines són la i les","Finalment, s''utilitzen per a designar coses o persones conegudes"]'),
('valenciano', 'eso', '{1}', '["Per a redactar una descripció, hem d''observar atentament allò que descriurem","Després, apuntem les característiques més''importants i rellevants del tema","A continuació, ordenem aquestes idees de forma lògica al nostre escrit","Posteriorment, utilitzem adjectius variats per a enriquir el text","Finalment, revisem la descripció per a comprovar que està ben feta"]'),
('valenciano', 'eso', '{1}', '["L''oració simple està formada per un subjecte i un predicat","En primer lloc, el subjecte és qui realitza l''acció del verb","En segon lloc, el predicat és tot el que diem del subjecte","A més, el nucli del predicat sempre és''un verb conjugat","Finalment, aquesta estructura bàsica apareix en totes les oracions completes"]'),
('valenciano', 'eso', '{1}', '["Per a participar en un debat a classe, hem de preparar-nos bé","Primer, investiguem sobre el tema que anem a debatre amb els companys","Després, pensem els arguments a favor i en contra de les nostres idees","A continuació, escoltem respectuosament les opinions dels altres participants","Finalment, defensem les nostres idees amb educació i respecte"]'),
('valenciano', 'eso', '{1}', '["Els adverbis són paraules invariables que modifiquen diferents elements de l''oració","En primer lloc, poden modificar verbs, adjectius o altres adverbis","En segon lloc, expressen lloc, temps, manera o quantitat","A més, no concorden amb cap altre element de l''oració","Finalment, aporten informació circumstancial sobre l''acció principal"]'),
('valenciano', 'eso', '{1}', '["Per a escriure una poesia senzilla, primer triem un tema que ens inspire","Després, pensem les paraules que rimen entre si per als versos","A continuació, organitzem aquestes paraules formant versos amb ritme","Posteriorment, agrupem els versos en estrofes segons l''estructura triada","Finalment, llegim la poesia en veu alta per a comprovar el seu so"]'),
('valenciano', 'eso', '{1}', '["Les preposicions són paraules invariables que relacionen elements dins d''una oració","En primer lloc, hi ha preposicions simples com a, de, en, per","En segon lloc, també existeixen les locucions preposicionals com davant de","A més, sempre van seguides d''un substantiu o d''un pronom","Finalment, introdueixen complements que amplien la informació del verb"]'),
('valenciano', 'eso', '{1}', '["Per a llegir un llibre correctament, primer mirem la portada amb atenció","Després, llegim el resum per a saber de què tracta l''obra","A continuació, comencem la lectura capítol per capítol amb calma","Posteriorment, anotem les paraules noves que trobem al nostre quadern","Finalment, escrivim un comentari sobre la nostra experiència lectora"]'),
('valenciano', 'eso', '{1}', '["Les conjuncions són paraules que uneixen oracions o parts d''una oració","En primer lloc, les copulatives com i, ni afegeixen informació nova","En segon lloc, les adversatives com però expressen oposició entre idees","A més, les disjuntives com o presenten alternatives al lector","Finalment, ajuden a crear textos més complexos i ben estructurats"]'),
('valenciano', 'eso', '{1}', '["Per a estudiar valencià eficaçment, necessitem seguir un mètode organitzat","Primer, llegim atentament la lliçó del llibre de text","Després, subratllem els conceptes més''importants de cada apartat","A continuació, fem els exercicis practicant el que hem aprés","Finalment, repassem tot abans de l''examen per a consolidar els coneixements"]'),
('valenciano', 'eso', '{1}', '["Una notícia periodística sempre respon a sis preguntes fonamentals","En primer lloc, ha de dir qui són''els protagonistes del fet","En segon lloc, explica què ha passat exactament amb detall","A més, informa de quan i on va ocórrer l''esdeveniment","Finalment, explica per què ha succeït''i com ha afectat a la gent"]'),
('valenciano', 'eso', '{1}', '["Per a fer un treball escrit, primer escollim el tema que investigarem","Després, busquem informació en diverses fonts fiables i contrastades","A continuació, organitzem les idees en un esquema coherent i clar","Posteriorment, redactem el treball amb introducció, desenvolupament i conclusió","Finalment, revisem l''ortografia i la presentació abans d''entregar-lo"]'),
('valenciano', 'eso', '{1}', '["Els diftongs són la unió de dues vocals en una mateixa síl·laba","En primer lloc, es formen amb una vocal oberta i una tancada","En segon lloc, poden ser creixents o decreixents segons l''ordre","A més, no es consideren diftongs dues vocals obertes juntes","Finalment, és''important reconèixer-los per a la correcta accentuació de paraules"]'),
('valenciano', 'eso', '{1}', '["Per a participar activament a les classes de valencià, cal estar atent","Primer, escoltem amb interès les explicacions del professor de la matèria","Després, prenem apunts de les idees més''importants al quadern","A continuació, formulem preguntes quan alguna cosa no s''entén bé","Finalment, fem els deures per a consolidar el que hem aprés"]'),
('valenciano', 'eso', '{1}', '["El subjecte d''una oració és la persona, animal o cosa que realitza l''acció","En primer lloc, per a identificar-lo preguntem al verb qui o què","En segon lloc, pot estar format per un substantiu o un pronom","A més, pot anar acompanyat de determinants o d''adjectius","Finalment, concorda sempre amb el verb en nombre i persona"]'),
('valenciano', 'eso', '{1}', '["Per a preparar una exposició oral, primer triem bé el tema","Després, busquem informació interessant sobre el tema en diverses fonts","A continuació, organitzem les idees principals en un esquema clar","Posteriorment, practiquem l''exposició diverses vegades davant del mirall","Finalment, presentem el treball davant dels companys amb confiança"]'),
('valenciano', 'eso', '{1}', '["Les paraules sinònimes tenen el mateix significat o molt semblant","En primer lloc, ens ajuden a no repetir les mateixes paraules","En segon lloc, enriqueixen el vocabulari que utilitzem als textos","A més, permeten expressar els matisos d''una idea amb més precisió","Finalment, es busquen fàcilment en els diccionaris específics de sinònims"]'),
('valenciano', 'eso', '{1}', '["Per a conjugar un verb regular, primer identifiquem la conjugació corresponent","Després, separem l''arrel de la terminació de l''infinitiu","A continuació, afegim a l''arrel les desinències pròpies del temps","Posteriorment, comprovem que la forma resultant concorde amb el subjecte","Finalment, utilitzem el verb correctament dins de l''oració"]'),
('valenciano', 'eso', '{1}', '["El narrador d''una història pot ser de diferents tipus segons el cas","En primer lloc, el narrador omniscient sap tot el que pensen els personatges","En segon lloc, el narrador protagonista narra en primera persona les seues aventures","A més, el narrador testimoni conta el que veu com a espectador","Finalment, cada tipus de narrador aporta una perspectiva diferent al relat"]'),
('valenciano', 'eso', '{1}', '["Per a memoritzar un poema, llegim primer el text complet diverses vegades","Després, entenem bé el significat de cada vers i estrofa","A continuació, repetim cada vers en veu alta fins a memoritzar-lo","Posteriorment, ajuntem els versos per a recitar estrofes completes","Finalment, recitem tota la poesia sense necessitat de mirar el paper"]'),
('valenciano', 'eso', '{1}', '["Els diminutius són paraules que expressen menor grandària o afecte","En primer lloc, es formen afegint sufixos com et, eta a la paraula","En segon lloc, indiquen que alguna cosa és xicoteta o menuda","A més, poden expressar afecte o carinyo cap a persones o animals","Finalment, s''utilitzen molt en la parla col·loquial quotidiana"]'),
('valenciano', 'eso', '{1}', '["Per a fer una redacció llarga, comencem amb un esquema previ","Després, escrivim una introducció atractiva per a captar l''atenció","A continuació, desenvolupem el cos principal amb els arguments ordenats","Posteriorment, afegim exemples per a il·lustrar les idees exposades","Finalment, tanquem amb una conclusió clara i ben raonada"]'),
('valenciano', 'eso', '{1}', '["Les paraules antònimes expressen significats oposats o contraris entre si","En primer lloc, s''utilitzen per a crear contrastos en els textos","En segon lloc, poden formar-se afegint prefixos negatius a la paraula","A més, també n''hi ha que no tenen cap relació morfològica","Finalment, enriqueixen l''expressió escrita i oral de qualsevol parlant"]'),
('valenciano', 'eso', '{1}', '["Per a llegir en veu alta correctament, primer respectem els signes de puntuació","Després, utilitzem l''entonació adequada a cada frase del text","A continuació, pronunciem bé totes les paraules sense ometre cap lletra","Posteriorment, mantenim un ritme constant i apropiat durant la lectura","Finalment, transmetem emoció i significat al text llegit amb expressivitat"]'),
('valenciano', 'eso', '{1}', '["L''ordre alfabètic ens ajuda a organitzar les paraules de manera lògica","En primer lloc, mirem la primera lletra de cada paraula a ordenar","En segon lloc, si coincideix comparem la segona lletra de cada paraula","A més, continuem comparant lletres fins a trobar una diferència","Finalment, col·loquem cada paraula en la posició que li correspon"]'),
('valenciano', 'eso', '{1}', '["Per a aprendre vocabulari nou, fem diverses activitats interessants a classe","Primer, llegim textos variats on apareixen les paraules noves","Després, busquem el significat d''aquestes paraules al diccionari","A continuació, escrivim oracions completes utilitzant cada paraula apresa","Finalment, repetim aquest procés fins a memoritzar totes les paraules"]'),
('valenciano', 'eso', '{1}', '["La descripció d''un personatge segueix una estructura ordenada normalment","En primer lloc, descrivim l''aspecte físic del personatge amb detalls","En segon lloc, expliquem com va vestit en aquell moment concret","A més, parlem del seu caràcter i la seua personalitat","Finalment, mencionem les seues aficions i les coses que li agraden"]'),
('valenciano', 'eso', '{1}', '["Per a identificar els errors ortogràfics d''un text, cal revisar-lo amb atenció","Primer, llegim el text sencer de principi a fi","Després, tornem a llegir fixant-nos només''en les paraules difícils","A continuació, busquem al diccionari les paraules que ens fan dubtar","Finalment, corregim les faltes trobades amb un bolígraf de color"]'),
('valenciano', 'eso', '{1}', '["Les paraules primitives són''aquelles que no deriven d''altres paraules","En primer lloc, estan formades només per una arrel principal","En segon lloc, de les primitives podem formar paraules derivades","A més, serveixen de base per a crear famílies lèxiques completes","Finalment, són fonamentals per a entendre com es formen les paraules"]'),
('valenciano', 'eso', '{1}', '["Per a escriure correctament en valencià, és''essencial conèixer les regles","Primer, estudiem les regles d''accentuació gràfica de les paraules","Després, aprenem les normes sobre l ús de la be i la ve","A continuació, practiquem amb exercicis variats i dictats","Finalment, revisem tot el que escrivim amb molta atenció"]'),
('valenciano', 'eso', '{1}', '["El text narratiu té una estructura clàssica molt ben definida","En primer lloc, presenta els personatges i la situació inicial","En segon lloc, planteja un conflicte o problema que cal resoldre","A més, desenvolupa l''acció amb diverses aventures del protagonista","Finalment, arriba al desenllaç on tot es resol definitivament"]'),
('valenciano', 'eso', '{1}', '["Per a memoritzar les formes verbals, practiquem de diverses maneres","Primer, escrivim les conjugacions completes al nostre quadern","Després, repetim les formes en veu alta per a recordar-les millor","A continuació, fem exercicis de conjugació amb verbs diferents","Finalment, utilitzem els verbs en oracions que nosaltres mateixos creem"]'),
('valenciano', 'eso', '{1}', '["Les paraules homòfones es pronuncien igual però s''escriuen diferent","En primer lloc, tenen significats diferents segons el context","En segon lloc, cal prestar molta atenció per a no confondre-les","A més, la seua ortografia correcta depèn del significat concret","Finalment, només la pràctica constant ajuda a dominar-les perfectament"]'),
('valenciano', 'eso', '{1}', '["Per a entendre un text difícil, cal utilitzar diverses estratègies de lectura","Primer, llegim el text complet per a tenir una idea general","Després, identifiquem les paraules que no coneixem del text","A continuació, busquem el significat d''aquestes paraules al diccionari","Finalment, tornem a llegir el text amb major comprensió"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'eso', '{2}', '["Tirant lo Blanch és''una novel·la cavalleresca escrita per Joanot Martorell","L''obra es va publicar a València l''any mil quatre-cents noranta","El protagonista és''un jove cavaller bretó anomenat Tirant","Viu moltes aventures per Europa lluitant contra els enemics","Finalment, la novel·la és considerada una obra mestra de la literatura"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles substitueixen complements del verb dins d''una oració","En primer lloc, tenen formes diferents segons la posició davant o darrere","En segon lloc, poden anar abans del verb o enganxats a ell","A més, cal aprendre les seues formes plenes i reforçades","Finalment, el seu ús correcte és fonamental en valencià escrit"]'),
('valenciano', 'eso', '{2}', '["Joanot Martorell va nàixer a Gandia l''any mil quatre-cents tretze","Era membre d''una família noble valenciana de gran prestigi social","Durant la seua vida va viatjar per diverses corts europees","Allà va conèixer les tradicions cavalleresques que inspirarien la seua obra","Finalment, va escriure Tirant lo Blanch durant els últims anys de la seua vida"]'),
('valenciano', 'eso', '{2}', '["Per a substituir el complement directe, utilitzem el pronom feble el o la","En primer lloc, concorda amb el gènere i nombre del substantiu substituït","En segon lloc, les formes plurals són''els i les","A més, es col·loca davant del verb en la majoria dels casos","Finalment, aquest ús''evita repeticions innecessàries al text"]'),
('valenciano', 'eso', '{2}', '["En el primer capítol de Tirant lo Blanch, el cavaller coneix el comte Guillem","El comte li explica què significa ser cavaller i les seues obligacions","Després, Tirant viatja a Anglaterra per a participar en les festes de casament","Allà destaca als tornejos i demostra la seua gran valentia","Finalment, és''armat cavaller i comença la seua gran aventura"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles de primera persona són''em i ens","En primer lloc, em s''utilitza per al singular en totes les funcions","En segon lloc, ens s''utilitza per al plural en totes les funcions","A més, davant de vocal em es converteix en m","Finalment, aquestes formes són bàsiques per a construir oracions correctes"]'),
('valenciano', 'eso', '{2}', '["Per a analitzar un text literari, primer identifiquem el gènere literari","Després, estudiem l''estructura i les parts que el componen","A continuació, analitzem els personatges principals i secundaris","Posteriorment, identifiquem els recursos estilístics que utilitza l''autor","Finalment, interpretem el missatge i la intenció del text"]'),
('valenciano', 'eso', '{2}', '["La llegenda de Sant Jordi i el drac és molt popular a València","Al principi, un drac aterroritzava un poble sencer devorant animals","Després, el poble va començar a sacrificar persones per a calmar-lo","Un dia, va tocar a la filla del rei ser sacrificada","Finalment, Sant Jordi va arribar i va matar el drac salvant la princesa"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles de segona persona són''et i us","En primer lloc, et s''utilitza per al tractament de tu","En segon lloc, us s''utilitza per al tractament plural","A més, davant de vocal et es converteix en t","Finalment, el seu ús correcte mostra respecte cap a l''interlocutor"]'),
('valenciano', 'eso', '{2}', '["Per a escriure un comentari literari ben estructurat, seguim diversos passos","Primer, fem una presentació breu de l''obra i l''autor","Després, contextualitzem l''obra en el seu moment històric","A continuació, analitzem el contingut i els temes principals","Finalment, oferim una valoració personal argumentada sobre l''obra"]'),
('valenciano', 'eso', '{2}', '["Ausiàs March va ser un dels poetes més''importants del segle quinze","Va nàixer a València l''any mil tres-cents noranta-set","La seua obra poètica tracta sobre l''amor, la mort i Déu","Va escriure en valencià trencant amb la tradició provençal anterior","Finalment, els seus poemes són''una joia de la literatura medieval"]'),
('valenciano', 'eso', '{2}', '["El pronom feble hi substitueix complements circumstancials de lloc","En primer lloc, reemplaça expressions que indiquen on es realitza l''acció","En segon lloc, es col·loca davant del verb en la majoria dels casos","A més, també pot substituir altres tipus de complements circumstancials","Finalment, el seu ús''és molt característic del valencià culte"]'),
('valenciano', 'eso', '{2}', '["Per a fer una exposició oral sobre un llibre, preparem els materials","Primer, llegim atentament el llibre i anotem les idees importants","Després, fem un esquema amb l''estructura de la nostra presentació","A continuació, preparem diapositives o imatges per a il·lustrar","Finalment, assagem davant del mirall abans d''exposar davant la classe"]'),
('valenciano', 'eso', '{2}', '["Jaume Roig va ser un metge i escriptor valencià del segle quinze","Va escriure una obra satírica titulada Espill o Llibre de les dones","En ella, critica durament els defectes femenins de la seua època","L''obra està escrita en versos de quatre síl·labes característics","Finalment, és''una important mostra de la literatura medieval valenciana"]'),
('valenciano', 'eso', '{2}', '["El pronom feble en substitueix complements introduïts per la preposició de","En primer lloc, pot substituir un complement del nom introduït per de","En segon lloc, també substitueix el complement partitiu","A més, es col·loca davant del verb generalment","Finalment, és''un dels pronoms més útils i freqüents en valencià"]'),
('valenciano', 'eso', '{2}', '["La tradició oral valenciana conserva moltes llegendes antigues i curioses","Algunes expliquen l''origen de ciutats i pobles de la nostra terra","Unes altres narren fets històrics de manera llegendària i fantàstica","Moltes altres parlen de personatges misteriosos com bruixes o follets","Finalment, aquestes llegendes formen part del nostre patrimoni cultural"]'),
('valenciano', 'eso', '{2}', '["Per a preparar un examen de literatura, estudiem de forma organitzada","Primer, fem un resum de cada obra i autor del temari","Després, memoritzem les dates i els fets històrics més rellevants","A continuació, practiquem amb preguntes d''exàmens anteriors","Finalment, repassem tot el material el dia abans de l''examen"]'),
('valenciano', 'eso', '{2}', '["Isabel de Villena va ser una escriptora valenciana del segle quinze","Va ser abadessa del monestir de la Trinitat de València","La seua obra més coneguda és la Vita Christi de tradició religiosa","En ella mostra una visió molt humana dels personatges de l''Evangeli","Finalment, és''una de les poques autores medievals valencianes conegudes"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles es combinen de manera complexa en algunes oracions","En primer lloc, quan s''ajunten dos pronoms de persones diferents","En segon lloc, cal respectar un ordre concret en la combinació","A més, poden canviar la seua forma segons el context","Finalment, aquesta combinació requereix pràctica i atenció per dominar-la"]'),
('valenciano', 'eso', '{2}', '["Per a redactar un text argumentatiu, cal defensar una idea clarament","Primer, plantegem la tesi que volem defendre al lector","Després, presentem els arguments a favor amb exemples concrets","A continuació, refutem els possibles arguments contraris","Finalment, concloem reforçant la nostra tesi inicial amb convicció"]'),
('valenciano', 'eso', '{2}', '["La Cançó de Roland és''una obra èpica medieval europea molt famosa","Narra les gestes del cavaller Roland al servei de Carlemany","L''acció es desenvolupa durant les guerres contra els musulmans","L''heroi mor defenent el seu rei amb honor i valentia","Finalment, aquesta obra va inspirar la literatura cavalleresca posterior"]'),
('valenciano', 'eso', '{2}', '["Per a usar correctament el pronom ho, cal conèixer la seua funció","En primer lloc, substitueix oracions subordinades completes dins d''una oració","En segon lloc, també pot substituir un adjectiu atribut","A més, sempre té un valor neutre sense gènere ni nombre","Finalment, el seu ús correcte distingeix el parlant culte del vulgar"]'),
('valenciano', 'eso', '{2}', '["Ramon Llull va ser un important filòsof i escriptor mallorquí medieval","Va escriure moltes obres en llengua catalana i llatina","Les seues idees filosòfiques van influir tota l''Europa medieval","També va viatjar molt intentant convertir els musulmans al cristianisme","Finalment, és considerat el pare de la literatura catalana"]'),
('valenciano', 'eso', '{2}', '["Per a llegir una obra clàssica, hem de preparar-nos adequadament","Primer, cerquem informació sobre l''autor i el context històric","Després, llegim una introducció crítica si n''hi ha disponible","A continuació, llegim el text amb calma i atenció","Finalment, reflexionem sobre els temes i el missatge de l''obra"]'),
('valenciano', 'eso', '{2}', '["Els trobadors eren poetes medievals que componien i cantaven poemes","Viatjaven de cort en cort entretenint els nobles de l''època","Els seus poemes tractaven principalment sobre l''amor cortès","Escrivien en occità, una llengua romànica del sud de França","Finalment, la seua tradició va influir molt en la poesia medieval europea"]'),
('valenciano', 'eso', '{2}', '["Per a fer un dictat en valencià, necessitem concentració i coneixement","Primer, escoltem tota la frase abans de començar a escriure","Després, escrivim respectant les pauses marcades per la puntuació","A continuació, prestem atenció a les paraules amb ortografia difícil","Finalment, revisem el text per a corregir possibles errors"]'),
('valenciano', 'eso', '{2}', '["La figura del cavaller medieval era un ideal de la societat feudal","Els cavallers havien de ser valents al camp de batalla","També havien de mostrar respecte envers les dames de la cort","Seguien un codi d''honor molt estricte anomenat cavalleria","Finalment, moltes obres literàries van reflectir aquest ideal cavalleresc"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles reflexius són''em, et, es, ens, us, es","En primer lloc, indiquen que el subjecte rep l''acció del verb","En segon lloc, acompanyen els verbs pronominals típicament reflexius","A més, cada persona té la seua forma específica corresponent","Finalment, el seu ús correcte és''essencial en la llengua escrita"]'),
('valenciano', 'eso', '{2}', '["Per a crear un diàleg literari, pensem en els personatges que parlaran","Primer, definim la personalitat i el caràcter de cada personatge","Després, pensem el tema sobre el qual conversaran entre si","A continuació, escrivim els torns de paraula amb naturalitat","Finalment, utilitzem els signes de puntuació adequats per al diàleg"]'),
('valenciano', 'eso', '{2}', '["L''amor cortès''era un tema central en la literatura medieval","El cavaller adorava una dama casada amb un altre senyor","L''havia de servir amb fidelitat sense esperar cap recompensa física","Els trobadors compongueren moltes cançons sobre aquest tipus d''amor","Finalment, aquesta concepció va influir tota la lírica medieval europea"]'),
('valenciano', 'eso', '{2}', '["Per a analitzar un poema, identifiquem primer el tipus de vers","Després, estudiem la rima i l''estructura de les estrofes","A continuació, analitzem els recursos literaris utilitzats pel poeta","Posteriorment, interpretem el significat i les emocions expressades","Finalment, valorem l''obra dins del context literari corresponent"]'),
('valenciano', 'eso', '{2}', '["Els romanços són composicions poètiques populars de tradició oral","Es cantaven a l''Edat Mitjana i es transmetien de generació en generació","Normalment narren històries d''amor, de guerra o de crims famosos","Estan escrits en versos octosíl·labs amb rima assonant","Finalment, constitueixen una part important del patrimoni literari popular"]'),
('valenciano', 'eso', '{2}', '["Per a col·locar correctament els pronoms febles, seguim unes regles","En primer lloc, amb verbs en indicatiu, van davant del verb","En segon lloc, amb infinitius i gerundis, van darrere enganxats","A més, amb imperatius afirmatius, també van enganxats al verb","Finalment, la pràctica constant ajuda a interioritzar aquestes regles"]'),
('valenciano', 'eso', '{2}', '["Sant Vicent Ferrer va ser un dominicà valencià molt famós","Va predicar per tot Europa durant el segle quinze","Els seus sermons eren molt populars entre la gent del poble","Escrivia en valencià del seu temps amb un estil directe","Finalment, és''una figura fonamental de la història valenciana"]'),
('valenciano', 'eso', '{2}', '["Per a escriure una ressenya crítica, primer llegim l''obra completa","Després, anotem les nostres impressions durant la lectura","A continuació, analitzem els aspectes positius i negatius","Posteriorment, comparem l''obra amb altres del mateix gènere","Finalment, expressem la nostra opinió argumentada sobre l''obra"]'),
('valenciano', 'eso', '{2}', '["La Crònica de Jaume I és''una obra històrica molt important medieval","El rei mateix va dictar el text explicant les seues gestes","Conta la conquesta de Mallorca, València i altres territoris","L''obra està escrita en primera persona del singular","Finalment, és''un document històric i literari de gran valor"]'),
('valenciano', 'eso', '{2}', '["Els pronoms febles tenen quatre formes diferents segons la posició","En primer lloc, la forma reforçada apareix davant del verb","En segon lloc, la forma plena s''usa davant de verbs amb vocal","A més, la forma elidida apareix darrere de verbs amb vocal","Finalment, la forma reduïda s''usa darrere de verbs amb consonant"]'),
('valenciano', 'eso', '{2}', '["Per a memoritzar els pronoms febles, practiquem amb exercicis variats","Primer, omplim buits amb el pronom adequat en cada oració","Després, substituïm''els complements pel pronom corresponent","A continuació, combinem dos pronoms en una mateixa oració","Finalment, utilitzem els pronoms en redaccions pròpies"]'),
('valenciano', 'eso', '{2}', '["Bernat Metge va ser un escriptor català del segle catorze","Va escriure Lo Somni, una obra humanista molt important","En ella dialoga amb el rei mort sobre qüestions filosòfiques","Mostra la influència dels clàssics grecs i llatins","Finalment, és''un precursor de l''humanisme renaixentista al nostre país"]'),
('valenciano', 'eso', '{2}', '["Per a identificar els pronoms febles en un text, cal llegir amb atenció","Primer, busquem paraules curtes davant o darrere dels verbs","Després, analitzem la seua funció dins de l''oració concreta","A continuació, determinem el seu referent en el context","Finalment, comprovem si el seu ús''és correcte"]'),
('valenciano', 'eso', '{2}', '["La literatura cavalleresca va ser molt popular durant l''Edat Mitjana","Narrava les aventures de cavallers valents per tot el món","Els protagonistes lluitaven contra monstres, gegants i mags","També defensaven dames indefenses dels enemics malvats","Finalment, Tirant lo Blanch és l''obra cim d''aquest gènere"]'),
('valenciano', 'eso', '{2}', '["Per a estudiar l''obra Tirant lo Blanch, seguim un mètode ordenat","Primer, llegim fragments representatius dels principals episodis","Després, analitzem els personatges més''importants de la novel·la","A continuació, estudiem el context històric en què es va escriure","Finalment, reflexionem sobre la importància de l''obra en la literatura"]'),
('valenciano', 'eso', '{2}', '["Els cantars de gesta narraven les gestes d''herois llegendaris","Es cantaven en places i festes medievals davant del públic","Els joglars els aprenien de memòria i els recitaven amb música","Els herois eren models de valentia i honor per a la societat","Finalment, aquests cantars van ser l''origen de la literatura èpica medieval"]'),
('valenciano', 'eso', '{2}', '["Per a fer una traducció bàsica entre valencià i castellà, seguim passos","Primer, llegim el text original per a entendre el significat","Després, identifiquem les paraules que poden causar dificultats","A continuació, busquem els equivalents al diccionari bilingüe","Finalment, redactem el text traduït respectant el sentit original"]'),
('valenciano', 'eso', '{2}', '["Les novel·les de cavalleries tenien uns elements característics molt definits","Primer de tot, presenten un heroi cavaller de gran valentia","En segon lloc, narren les seues aventures a diferents llocs","A més, inclouen elements meravellosos i personatges fantàstics","Finalment, acaben normalment amb el triomf del bé sobre el mal"]'),
('valenciano', 'eso', '{2}', '["Per a escriure un conte propi, imagino primer els personatges principals","Després, creo una situació inicial amb un problema clar","A continuació, desenvolupe les aventures dels personatges al llarg del conte","Posteriorment, arribo al moment culminant de la història","Finalment, escric un desenllaç satisfactori per als lectors"]'),
('valenciano', 'eso', '{2}', '["La literatura medieval valenciana va tenir el seu moment de màxima esplendor","Durant el segle quinze es van escriure les millors obres","Autors com Ausiàs March, Joanot Martorell i Isabel de Villena destaquen","Les seues obres encara avui són reconegudes internacionalment","Finalment, aquest període és conegut com el Segle d''Or valencià"]'),
('valenciano', 'eso', '{2}', '["Per a aprendre els verbs irregulars del valencià, cal molta pràctica","Primer, identifiquem els verbs més comuns en la llengua quotidiana","Després, estudiem les seues formes principals en diferents temps","A continuació, memoritzem les irregularitats més''importants i difícils","Finalment, practiquem amb exercicis i exemples contextualitzats"]'),
('valenciano', 'eso', '{2}', '["Els valencians hem conservat la nostra llengua durant segles","Des del segle tretze quan el rei Jaume I va conquerir València","Hem mantingut la llengua malgrat les dificultats històriques viscudes","Els escriptors han cuidat i enriquit el nostre patrimoni lingüístic","Finalment, avui el valencià és''una llengua amb futur i vitalitat"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'eso', '{3}', '["La Renaixença valenciana va ser un moviment cultural del segle dinou","Tenia com a objectiu recuperar la nostra llengua i cultura","Els escriptors van tornar a utilitzar el valencià literari després de segles","Figures com Teodor Llorente van liderar aquest moviment renaixentista","Finalment, va servir per a dignificar novament la nostra literatura"]'),
('valenciano', 'eso', '{3}', '["Les oracions subordinades substantives tenen funcions del substantiu dins l''oració","En primer lloc, poden ser el subjecte de l''oració principal","En segon lloc, funcionen com a complement directe del verb principal","A més, poden exercir com a complement del nom o atribut","Finalment, el seu reconeixement requereix pràctica d''anàlisi sintàctica"]'),
('valenciano', 'eso', '{3}', '["Teodor Llorente va ser un dels principals poetes de la Renaixença","Va nàixer a València l''any mil vuit-cents trenta-sis","La seua obra principal és''el llibre Llibret de versos","En ella canta l''amor a la terra i les tradicions valencianes","Finalment, és considerat el poeta nacional de la Renaixença valenciana"]'),
('valenciano', 'eso', '{3}', '["Les oracions subordinades adjectives qualifiquen un substantiu de l''oració principal","En primer lloc, sempre van introduïdes per un pronom relatiu","En segon lloc, l''antecedent és''el substantiu que modifiquen","A més, realitzen la mateixa funció que un adjectiu qualificatiu","Finalment, aporten informació addicional sobre l''antecedent mencionat"]'),
('valenciano', 'eso', '{3}', '["Els Jocs Florals eren certàmens literaris propis de la Renaixença","S''organitzaven cada any al mes de juliol a València","Els poetes presentaven les seues obres per a concursar","Els premis principals eren la flor natural, l''englantina i la viola","Finalment, van ser molt importants per a la difusió de la nova literatura"]'),
('valenciano', 'eso', '{3}', '["Les oracions subordinades adverbials complementen el verb de l''oració principal","En primer lloc, expressen circumstàncies com temps, lloc o manera","En segon lloc, poden ser causals, finals o condicionals","A més, cadascuna es construeix amb un nexe específic","Finalment, són''essencials per a construir textos complexos i rics"]'),
('valenciano', 'eso', '{3}', '["Vicent Wenceslau Querol va ser un altre poeta destacat de la Renaixença","La seua obra combina el valencià amb el castellà culte","Els seus poemes mostren una gran sensibilitat romàntica","També va ser un amic íntim del poeta Teodor Llorente","Finalment, va contribuir amb obres importants al ressorgiment cultural"]'),
('valenciano', 'eso', '{3}', '["La subordinació permet unir oracions simples per a formar oracions complexes","Primer, una oració principal conté el nucli del significat","Després, una o més''oracions subordinades depenen de la principal","A més, es connecten mitjançant enllaços subordinants específics","Finalment, aquest mecanisme enriqueix l''expressió escrita i oral"]'),
('valenciano', 'eso', '{3}', '["Constantí Llombart va ser el veritable impulsor de la Renaixença valenciana","Va fundar Lo Rat Penat l''any mil vuit-cents setanta-vuit","Aquesta societat defensava la llengua i cultura valencianes","Va publicar nombroses obres i articles en valencià","Finalment, el seu treball va ser fonamental per a la recuperació lingüística"]'),
('valenciano', 'eso', '{3}', '["Les oracions causals expliquen la causa o raó de l''acció principal","En primer lloc, van introduïdes per nexes com perquè, ja que","En segon lloc, poden anar abans o després de l''oració principal","A més, responen a la pregunta per quina raó","Finalment, són bàsiques per a justificar i argumentar en qualsevol text"]'),
('valenciano', 'eso', '{3}', '["La societat Lo Rat Penat va ser fundada a València en mil vuit-cents setanta-vuit","El seu objectiu principal era defendre la llengua i cultura valencianes","Organitzava activitats com els Jocs Florals i classes de valencià","Els seus membres escrivien poesia i prosa en valencià","Finalment, encara avui continua existint mantenint la seua tasca cultural"]'),
('valenciano', 'eso', '{3}', '["Les oracions finals expressen la finalitat o objectiu de l''acció principal","En primer lloc, van introduïdes per nexes com perquè, per tal que","En segon lloc, el verb subordinat va normalment en subjuntiu","A més, responen a la pregunta amb quina finalitat","Finalment, són fonamentals per a expressar propòsits i intencions"]'),
('valenciano', 'eso', '{3}', '["La premsa valenciana va ser molt important durant la Renaixença","Publicacions com El Mole van contribuir a la difusió del valencià","Aquestes publicacions mesclaven articles seriosos i humor popular","Arribaven a lectors de totes les classes socials valencianes","Finalment, van ser vehicles fonamentals del moviment renaixentista"]'),
('valenciano', 'eso', '{3}', '["Les oracions condicionals expressen una condició per a l''acció principal","En primer lloc, van introduïdes pel nexe si en la majoria dels casos","En segon lloc, poden ser reals, possibles o irreals","A més, cada tipus utilitza uns temps verbals diferents","Finalment, el seu domini és''essencial per a expressar hipòtesis complexes"]'),
('valenciano', 'eso', '{3}', '["La literatura romàntica europea va influir directament la Renaixença valenciana","Els romàntics defensaven el retorn a les tradicions populars","Valoraven la naturalesa, els sentiments i la llibertat individual","Aquests temes es veuen en els poetes renaixentistes valencians","Finalment, aquesta influència va ser clau per al caràcter del moviment"]'),
('valenciano', 'eso', '{3}', '["Les oracions concessives expressen una dificultat que no impedeix l''acció","En primer lloc, van introduïdes per nexes com encara que, tot i que","En segon lloc, poden tenir el verb en indicatiu o subjuntiu","A més, aquesta elecció depèn del caràcter real o hipotètic","Finalment, permeten expressar contrastos i oposicions dins del text"]'),
('valenciano', 'eso', '{3}', '["Jacint Labaila va ser un altre autor important de la Renaixença","Va nàixer a València l''any mil vuit-cents tretze","Els seus poemes tractaven temes locals i costumistes","Va participar activament en els Jocs Florals valencians","Finalment, la seua obra forma part del patrimoni literari valencià"]'),
('valenciano', 'eso', '{3}', '["Les oracions consecutives expressen la conseqüència d''un fet anterior","En primer lloc, van introduïdes per nexes com tant que, de manera que","En segon lloc, necessiten un element intensificador a l''oració principal","A més, expliquen el resultat lògic d''una situació descrita","Finalment, ajuden a mostrar relacions de causa i efecte"]'),
('valenciano', 'eso', '{3}', '["El context històric de la Renaixença era complex i interessant","Europa vivia una època de canvis socials i polítics importants","Naixien els nacionalismes a diferents territoris europeus","A València també es desperta el sentiment d''identitat pròpia","Finalment, tot això va afavorir el ressorgiment de la cultura local"]'),
('valenciano', 'eso', '{3}', '["Les oracions comparatives estableixen una comparació entre dos elements","En primer lloc, poden ser d''igualtat amb nexes com tan com","En segon lloc, poden expressar superioritat amb més que","A més, les d''inferioritat utilitzen menys que","Finalment, són útils per a establir relacions quantitatives o qualitatives"]'),
('valenciano', 'eso', '{3}', '["La prosa costumista va ser un gènere important durant la Renaixença","Descrivia les tradicions i la vida quotidiana dels valencians","Els autors retratistes pintaven escenes típiques amb gran detall","Les seues obres tenien sovint una finalitat didàctica i moralitzant","Finalment, ens ofereixen una valuosa visió del passat"]'),
('valenciano', 'eso', '{3}', '["Les oracions temporals indiquen quan passa l''acció de la principal","En primer lloc, van introduïdes per nexes com quan, mentre","En segon lloc, poden expressar simultaneïtat, anterioritat o posterioritat","A més, cada relació temporal té els seus nexes específics","Finalment, organitzen la informació cronològica dels textos narratius"]'),
('valenciano', 'eso', '{3}', '["La Reial Acadèmia de la Cultura Valenciana té una llarga història","Va ser creada per a defendre la nostra cultura i tradicions","Els seus membres són''experts en diferents camps del saber","Publica estudis i llibres sobre temes valencians importants","Finalment, juga un paper clau en la investigació cultural"]'),
('valenciano', 'eso', '{3}', '["Per a analitzar una oració composta, seguim diversos passos metòdics","Primer, identifiquem l''oració principal i la seua estructura","Després, localitzem les oracions subordinades amb els seus nexes","A continuació, classifiquem cada subordinada segons el seu tipus","Finalment, representem l''anàlisi gràficament per a major claredat"]'),
('valenciano', 'eso', '{3}', '["El valencià va ressorgir literàriament després de segles d ús restringit","Durant la Decadència s''havia utilitzat poc per a la literatura culta","Amb la Renaixença va tornar a ser llengua literària digna","Els escriptors van recuperar formes i vocabulari antic","Finalment, es va crear una base per a la literatura moderna valenciana"]'),
('valenciano', 'eso', '{3}', '["Les oracions modals indiquen la manera com es realitza l''acció","En primer lloc, van introduïdes per nexes com com, tal com","En segon lloc, el verb pot anar en indicatiu o subjuntiu","A més, poden també utilitzar formes no personals del verb","Finalment, afigen informació qualitativa a l''acció principal"]'),
('valenciano', 'eso', '{3}', '["La literatura de la Renaixença tenia diversos trets característics","Primer de tot, utilitzava el valencià com a llengua literària","En segon lloc, tractava temes locals i tradicionals","A més, seguia els models estètics del romanticisme europeu","Finalment, buscava la recuperació de la identitat cultural perduda"]'),
('valenciano', 'eso', '{3}', '["Per a escriure un text expositiu, organitzem la informació amb claredat","Primer, presentem el tema que anem a exposar al lector","Després, desenvolupem les idees de forma ordenada i lògica","A continuació, utilitzem exemples per a il·lustrar els conceptes","Finalment, sintetitzem les idees més''importants en la conclusió"]'),
('valenciano', 'eso', '{3}', '["Vicent Blasco Ibáñez va ser un escriptor valencià molt important","Va nàixer a València l''any mil vuit-cents seixanta-set","Les seues novel·les retraten la vida rural valenciana amb realisme","Obres com La Barraca i Canyes i fang són les més conegudes","Finalment, la seua fama va traspassar fronteres arribant a tot el món"]'),
('valenciano', 'eso', '{3}', '["Les oracions de relatiu introdueixen informació sobre un antecedent","En primer lloc, utilitzen pronoms relatius com que, qui","En segon lloc, poden ser explicatives o especificatives","A més, les explicatives van sempre entre comes","Finalment, les especificatives restringeixen el significat de l''antecedent"]'),
('valenciano', 'eso', '{3}', '["La literatura valenciana del segle dinou va reflectir els canvis socials","La industrialització transformava la vida de moltes famílies","Els escriptors van denunciar les injustícies de l''època","També van retratar les tradicions que corrien perill de desaparèixer","Finalment, els seus escrits són testimonis d''una època de canvis"]'),
('valenciano', 'eso', '{3}', '["Les diferents varietats dialectals del valencià presenten característiques pròpies","Primer, el valencià central és parlat a València ciutat i rodalies","Després, el valencià septentrional és típic del nord del territori","A més, el valencià meridional té els seus propis trets distintius","Finalment, aquesta diversitat enriqueix el nostre patrimoni lingüístic"]'),
('valenciano', 'eso', '{3}', '["L ús dels temps verbals en valencià requereix atenció als matisos","En primer lloc, l''indicatiu expressa fets reals i objectius","En segon lloc, el subjuntiu expressa dubte, desig o possibilitat","A més, l''imperatiu s''utilitza per a donar ordres directes","Finalment, cada mode té les seues regles d ús''específiques"]'),
('valenciano', 'eso', '{3}', '["La Fira del Llibre de València és''un esdeveniment cultural important","Se celebra anualment al centre de la ciutat durant uns dies","Hi participen editorials, llibreters, escriptors i lectors apassionats","Es presenten noves obres i es fan activitats culturals diverses","Finalment, és''un aparador fonamental per a la literatura valenciana"]'),
('valenciano', 'eso', '{3}', '["Per a comentar un fragment de text, seguim una estructura clara","Primer, situem el fragment en el context de l''obra i l''autor","Després, identifiquem el tema i les idees principals del text","A continuació, analitzem els recursos lingüístics utilitzats per l''autor","Finalment, oferim una valoració personal sobre el fragment"]'),
('valenciano', 'eso', '{3}', '["La Casa Regional dels Escriptors Valencians promou la cultura","Agrupa a escriptors de totes les generacions i estils literaris","Organitza presentacions de llibres i trobades culturals importants","També publica revistes amb articles i creacions literàries","Finalment, juga un paper clau en la promoció dels autors valencians"]'),
('valenciano', 'eso', '{3}', '["Les locucions verbals són''expressions fixes formades per diversos elements","En primer lloc, estan compostes per un verb més''un altre element","En segon lloc, tenen un significat diferent de la suma dels components","A més, funcionen com una única unitat verbal","Finalment, enriqueixen l''expressió amb matisos que no tenen les formes simples"]'),
('valenciano', 'eso', '{3}', '["La recuperació de textos medievals valencians va ser fonamental","Els estudiosos van buscar manuscrits antics a biblioteques i arxius","Aquests textos donaven a conèixer el passat literari valencià","Els poetes de la Renaixença s''inspiraven en aquests textos trobats","Finalment, es va reconstruir una tradició literària gairebé oblidada"]'),
('valenciano', 'eso', '{3}', '["Per a enriquir el nostre vocabulari, podem fer diverses activitats","Primer, llegim textos de diferents gèneres i temes variats","Després, anotem les paraules noves en un quadern personal","A continuació, busquem el seu significat i l''escrivim al costat","Finalment, utilitzem aquestes paraules en redaccions pròpies"]'),
('valenciano', 'eso', '{3}', '["El modernisme literari va substituir la Renaixença a finals del segle dinou","Buscava renovar estèticament la literatura amb noves formes i temes","Els escriptors modernistes tenien influències europees internacionals","A València també va tenir els seus representants destacats","Finalment, va marcar la transició cap a la literatura contemporània"]'),
('valenciano', 'eso', '{3}', '["Les oracions impersonals no tenen subjecte gramatical determinat","En primer lloc, inclouen verbs meteorològics com ploure, nevar","En segon lloc, usen construccions amb es passiva reflexa","A més, poden tenir l''estructura hi ha seguit d''un element","Finalment, es caracteritzen perquè no hi ha cap subjecte identificable"]'),
('valenciano', 'eso', '{3}', '["La historiografia romàntica valenciana va investigar el passat regional","Els autors buscaven documents i testimonis de l''època medieval","Escrivien obres que exaltaven les glòries del Regne de València","Aquesta visió del passat alimentava el sentiment identitari","Finalment, va contribuir a definir la consciència cultural valenciana"]'),
('valenciano', 'eso', '{3}', '["Per a fer una bona presentació oral, cal preparar-se bé amb antelació","Primer, investiguem a fons el tema que anem a presentar","Després, organitzem la informació en diapositives clares i atractives","A continuació, practiquem la presentació controlant els gestos i el to","Finalment, responem les preguntes del públic amb seguretat"]'),
('valenciano', 'eso', '{3}', '["La poesia popular valenciana té una llarga tradició oral","S''ha transmès de generació en generació al llarg dels segles","Inclou formes com les cançons de bressol i els romanços","També hi ha cançons de feina i de festes populars","Finalment, constitueix un patrimoni cultural de gran valor identitari"]'),
('valenciano', 'eso', '{3}', '["Les oracions coordinades estan formades per oracions del mateix rang","En primer lloc, estan unides per conjuncions coordinants específiques","En segon lloc, poden ser copulatives, adversatives o disjuntives","A més, també existeixen les explicatives i les distributives","Finalment, cada tipus té els seus nexes i característiques pròpies"]'),
('valenciano', 'eso', '{3}', '["La Renaixença va tenir un impacte cultural que va durar dècades","Va servir per a recuperar la consciència d''identitat valenciana","També va crear un espai per a la literatura culta en valencià","Els seus èxits van inspirar les generacions d''escriptors posteriors","Finalment, és''el moviment clau per a entendre la cultura valenciana moderna"]'),
('valenciano', 'eso', '{3}', '["Per a analitzar la mètrica d''un poema, comptem primer les síl·labes","Després, identifiquem el tipus de rima utilitzada pel poeta","A continuació, determinem l''estructura estròfica del conjunt","Posteriorment, busquem els possibles recursos rítmics i sonors","Finalment, relacionem tots aquests elements amb el contingut del poema"]'),
('valenciano', 'eso', '{3}', '["El valencià literari ha evolucionat des dels seus orígens medievals","Al principi era la llengua de la cort i la literatura culta","Durant la Decadència es va restringir el seu ús literari","Amb la Renaixença va ressorgir com a vehicle d''expressió artística","Finalment, actualment és''una llengua moderna i plenament viva"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'eso', '{4}', '["La literatura valenciana contemporània comença al segle vint amb noves propostes","Els escriptors busquen renovar les formes i temes tradicionals","Apareixen nous corrents estètics influenciats per Europa","La Guerra Civil suposa una ruptura dolorosa en aquest procés","Finalment, durant la postguerra es reprèn''amb força la producció literària"]'),
('valenciano', 'eso', '{4}', '["Per a fer un comentari de text complet, seguim una metodologia rigorosa","Primer, llegim el text diverses vegades per a comprendre a fons","Després, situem l''obra en el seu context històric i literari","A continuació, analitzem el contingut, la forma i els recursos estilístics","Finalment, oferim una interpretació global i una valoració crítica"]'),
('valenciano', 'eso', '{4}', '["Joan Fuster va ser un assagista i crític literari valencià fonamental","Va nàixer a Sueca l''any mil nou-cents vint-i-dos","La seua obra Nosaltres, els valencians va revolucionar el pensament","En ella analitza la identitat i la cultura valencianes amb esperit crític","Finalment, és considerat un dels intel·lectuals més''importants del segle vint"]'),
('valenciano', 'eso', '{4}', '["L''assaig modern valencià va nàixer amb la generació de la postguerra","Els assagistes analitzaven la realitat social i cultural del seu temps","Utilitzaven un estil reflexiu i sovint polèmic per a expressar idees","Les seues obres van contribuir al debat intel·lectual del país","Finalment, l''assaig és''un gènere amb tradició sòlida a València"]'),
('valenciano', 'eso', '{4}', '["Per a identificar la tesi d''un text argumentatiu, busquem la idea central","Primer, llegim el text complet per a captar-ne el sentit general","Després, identifiquem l''afirmació principal que l''autor defensa","A continuació, localitzem els arguments que donen suport a la tesi","Finalment, formulem la tesi amb les nostres pròpies paraules"]'),
('valenciano', 'eso', '{4}', '["Vicent Andrés''Estellés va ser un gran poeta contemporani valencià","Va nàixer a Burjassot l''any mil nou-cents vint-i-quatre","La seua obra poètica és molt extensa i variada temàticament","En ella mescla el llenguatge popular amb referents cultes i clàssics","Finalment, és considerat el poeta més''important del segle vint a València"]'),
('valenciano', 'eso', '{4}', '["La novel·la valenciana del segle vint va experimentar grans transformacions","Els autors van abandonar el costumisme per a buscar nous horitzons","Van assajar tècniques narratives modernes i innovadores","Els temes també es van diversificar reflectint la societat actual","Finalment, ha esdevingut un gènere ric i prestigiós"]'),
('valenciano', 'eso', '{4}', '["Per a analitzar les figures retòriques d''un text, les identifiquem primer","Després, explica l''efecte que produeix cadascuna en el lector","A continuació, relacionem aquestes figures amb el contingut del text","Posteriorment, valorem la seua contribució a l''estil de l''autor","Finalment, integrem aquesta anàlisi en el comentari global del text"]'),
('valenciano', 'eso', '{4}', '["Enric Valor va ser un escriptor i lingüista valencià molt respectat","Va dedicar la seua vida a recuperar rondalles populars valencianes","També va escriure importants estudis sobre gramàtica i lèxic","Les seues rondalles són considerades un tresor de la nostra cultura","Finalment, la seua tasca va ser fonamental per a la normalització lingüística"]'),
('valenciano', 'eso', '{4}', '["La literatura infantil i juvenil valenciana ha crescut molt en les últimes dècades","Nous autors escriuen històries adreçades als joves lectors","Les editorials publiquen obres de qualitat amb il·lustracions atractives","Els centres educatius promouen la lectura en valencià","Finalment, es forma una nova generació de lectors en la nostra llengua"]'),
('valenciano', 'eso', '{4}', '["Per a redactar una dissertació, organitzem les nostres idees de forma estructurada","Primer, formulem clarament la tesi que defensarem al llarg del text","Després, elaborem un esquema amb els arguments principals a utilitzar","A continuació, desenvolupem cada argument amb exemples i raonaments","Finalment, concloem recollint les idees principals i reafirmant la tesi"]'),
('valenciano', 'eso', '{4}', '["El teatre valencià contemporani té una llarga trajectòria de renovació","Des dels anys seixanta, nous dramaturgs exploren temes actuals","Busquen innovar en les formes escèniques i els llenguatges teatrals","També recuperen tradicions populars com el teatre de Nadal","Finalment, el teatre en valencià viu un moment de vitalitat creativa"]'),
('valenciano', 'eso', '{4}', '["Manuel Sanchis Guarner va ser un lingüista i filòleg valencià fonamental","Va estudiar a fons la història i estructura del valencià","La seua Gramàtica valenciana és''una obra de referència","També va investigar la dialectologia i la toponímia del país","Finalment, el seu llegat científic continua sent imprescindible"]'),
('valenciano', 'eso', '{4}', '["Per a fer un comentari lingüístic d''un text, analitzem les característiques idiomàtiques","Primer, identifiquem el registre utilitzat per l''autor al text","Després, analitzem el vocabulari i les possibles variants dialectals","A continuació, estudiem les estructures sintàctiques presents","Finalment, valorem com aquests elements contribueixen al significat global"]'),
('valenciano', 'eso', '{4}', '["La generació de la postguerra va mantenir viva la literatura valenciana","Va ser una època molt difícil per a la cultura en valencià","Tot i les restriccions, alguns escriptors van continuar creant obres","La publicació era complicada i sovint s''havia de fer a l''estranger","Finalment, gràcies a ells la literatura va sobreviure als anys més foscos"]'),
('valenciano', 'eso', '{4}', '["Per a identificar el tipus de text, analitzem diversos elements formals","Primer, mirem l''estructura i la longitud del text en general","Després, observem el llenguatge i el registre utilitzats per l''autor","A continuació, identifiquem la intenció comunicativa principal del text","Finalment, classifiquem el text segons la seua tipologia corresponent"]'),
('valenciano', 'eso', '{4}', '["Carmelina Sánchez-Cutillas va ser una escriptora valenciana destacada","La seua obra Matèria de Bretanya és''una novel·la memorable","En ella recrea records d''infantesa amb un estil poètic i suggerent","Va rebre diversos premis importants al llarg de la seua carrera","Finalment, és considerada una de les veus femenines més destacades"]'),
('valenciano', 'eso', '{4}', '["La poesia contemporània valenciana ha explorat múltiples estètiques i temes","Des de l''existencialisme fins al realisme crític i social","Els poetes han experimentat amb la forma i el llenguatge lliurement","També han dialogat amb la tradició literària catalana global","Finalment, és''una poesia viva amb moltes veus diferents"]'),
('valenciano', 'eso', '{4}', '["Per a comentar el context històric d''una obra, necessitem informació sòlida","Primer, investiguem els fets històrics més rellevants del període","Després, analitzem els corrents culturals dominants de l''època","A continuació, relacionem aquests elements amb la biografia de l''autor","Finalment, vinculem tot això amb els temes presents en l''obra"]'),
('valenciano', 'eso', '{4}', '["Martí Domínguez és''un escriptor valencià contemporani molt reconegut","Les seues novel·les combinen ciència, història i literatura de forma original","Obres com Els horts han guanyat importants premis literaris","També ha estat director d''algunes revistes culturals valencianes","Finalment, representa una veu original dins la literatura actual"]'),
('valenciano', 'eso', '{4}', '["La literatura valenciana moderna dialoga amb les tradicions europees","Els autors llegeixen i s''inspiren en escriptors internacionals","També mantenen vincles amb la resta de la literatura en català","Aquest diàleg enriqueix les seues obres amb múltiples referències","Finalment, sitúa la literatura valenciana en el context mundial"]'),
('valenciano', 'eso', '{4}', '["Per a comentar la figura del narrador en una novel·la, ens fixem en diversos aspectes","Primer, determinem quin tipus de narrador és present al text","Després, analitzem la seua relació amb els personatges i els fets","A continuació, observem la focalització utilitzada per l''autor","Finalment, valorem com tot això afecta la interpretació de l''obra"]'),
('valenciano', 'eso', '{4}', '["Isabel-Clara Simó va ser una escriptora alcoiana de gran prestigi","Va escriure novel·les, contes i assaigs al llarg de la seua vida","Els seus temes principals eren la identitat, el gènere i la història","Va rebre nombrosos premis literaris importants al nostre país","Finalment, la seua obra continua sent llegida i estudiada actualment"]'),
('valenciano', 'eso', '{4}', '["La renovació del teatre valencià va començar als anys seixanta","Les companyies independents buscaven un teatre compromès''i modern","Experimentaven amb tècniques d''avantguarda i nous llenguatges escènics","També recuperaven obres del patrimoni teatral valencià","Finalment, aquesta renovació va donar fruit en les dècades posteriors"]'),
('valenciano', 'eso', '{4}', '["Per a comentar l''estructura d''un text narratiu, identifiquem les seues parts","Primer, localitzem el plantejament inicial de la història","Després, seguim el desenvolupament del conflicte amb les seues etapes","A continuació, identifiquem el moment culminant o clímax","Finalment, analitzem el desenllaç i el tipus de final triat"]'),
('valenciano', 'eso', '{4}', '["Joan Francesc Mira és''un altre escriptor valencià contemporani molt important","Va nàixer a Castelló i és''antropòleg i novel·lista alhora","La seua obra combina reflexió cultural i creació literària de qualitat","Ha rebut premis importants com el Sant Jordi i el Joanot Martorell","Finalment, representa una figura clau del pensament valencià actual"]'),
('valenciano', 'eso', '{4}', '["La producció literària en valencià ha augmentat molt en les últimes dècades","Cada any es publiquen centenars de llibres nous en la nostra llengua","Hi ha editorials especialitzades que distribueixen aquestes obres","Els premis literaris valencians reconeixen les millors creacions","Finalment, la literatura en valencià gaudeix d''una salut notable"]'),
('valenciano', 'eso', '{4}', '["Per a comentar la funció dels personatges, identifiquem primer els principals","Després, classifiquem els personatges segons la seua importància a l''obra","A continuació, analitzem els seus trets psicològics i els seus comportaments","Posteriorment, estudiem les relacions entre ells al llarg del text","Finalment, relacionem els personatges amb el tema central de l''obra"]'),
('valenciano', 'eso', '{4}', '["La literatura d''opinió valenciana té una llarga tradició als mitjans","Els intel·lectuals escriuen articles per a diaris i revistes culturals","Aborden temes d''actualitat política, social i cultural del país","Aquests escrits influeixen en l''opinió pública valenciana","Finalment, formen part del ric patrimoni assagístic valencià"]'),
('valenciano', 'eso', '{4}', '["Per a estudiar les variants sociolingüístiques, analitzem diferents factors","Primer, observem com varia la llengua segons l''edat dels parlants","Després, mirem les diferències entre àmbits rurals i urbans","A continuació, estudiem la influència del nivell cultural en la parla","Finalment, relacionem aquestes variacions amb el context sociolingüístic"]'),
('valenciano', 'eso', '{4}', '["Ferran Torrent és''un autor valencià de novel·la negra contemporània","Les seues novel·les retraten la societat valenciana amb realisme i humor","Ambientades sovint a València, mostren els baixos fons urbans","Obres com Gràcies per la propina han tingut un gran èxit","Finalment, és''un dels autors més llegits en valencià actualment"]'),
('valenciano', 'eso', '{4}', '["Per a valorar críticament una obra literària, tenim en compte diversos factors","Primer, l''originalitat de la proposta i la qualitat de l''escriptura","Després, la coherència entre forma i contingut de l''obra","A continuació, la pertinència dels temes tractats per l''autor","Finalment, la capacitat de l''obra per a emocionar o fer reflexionar"]'),
('valenciano', 'eso', '{4}', '["La situació sociolingüística del valencià és complexa actualment","Hi ha una cooficialitat amb el castellà establerta legalment","L ús social varia segons zones, àmbits i generacions de parlants","S''han implementat polítiques per a la normalització lingüística","Finalment, el futur depèn del compromís de tots els valencians"]'),
('valenciano', 'eso', '{4}', '["Per a analitzar el lèxic d''un text, classifiquem les paraules en camps semàntics","Primer, identifiquem els mots que pertanyen al mateix camp","Després, observem les relacions semàntiques entre aquests mots","A continuació, analitzem la riquesa i varietat lèxica del text","Finalment, relacionem l ús del vocabulari amb el tema tractat"]'),
('valenciano', 'eso', '{4}', '["El premi Andròmina de narrativa és''un dels més prestigiosos en valencià","Es convoca cada any dins dels Premis Octubre de literatura","Ha premiat les millors novel·les i reculls de contes en valencià","Molts autors importants han rebut aquest reconeixement al llarg dels anys","Finalment, contribueix a promoure la literatura contemporània valenciana"]'),
('valenciano', 'eso', '{4}', '["Per a comentar l ús dels temps verbals, observem les seues funcions","Primer, identifiquem els temps dominants en el text analitzat","Després, analitzem l''alternança entre diferents temps al text","A continuació, relacionem aquests usos amb el tipus de text","Finalment, valorem com contribueixen al significat global de l''obra"]'),
('valenciano', 'eso', '{4}', '["Josep Piera és''un poeta valencià reconegut per la seua obra lírica","La seua poesia conjuga tradició i modernitat amb gran mestria","Ha escrit també obres en prosa de caràcter memorialístic","Les seues obres han estat traduïdes a diversos idiomes","Finalment, és''una de les veus més personals de la poesia contemporània"]'),
('valenciano', 'eso', '{4}', '["La crítica literària valenciana s''ocupa d''estudiar la producció contemporània","Els crítics analitzen les obres noves publicades cada any","Escriuen ressenyes per a revistes especialitzades i diaris","També participen en debats i presentacions de llibres","Finalment, el seu paper és''essencial per al prestigi de la literatura"]'),
('valenciano', 'eso', '{4}', '["Per a redactar un comentari de text, estructurem el treball amb claredat","Primer, comencem amb una introducció on presentem el text i l''autor","Després, desenvolupem el cos amb les diferents anàlisis pertinents","A continuació, passem de l''anàlisi formal a la interpretació de significats","Finalment, tanquem amb una conclusió que recull les idees principals"]'),
('valenciano', 'eso', '{4}', '["Gemma Lluch és''una investigadora valenciana especialitzada en literatura infantil","Ha escrit estudis sobre les formes narratives per a infants","També ha analitzat l''impacte de les noves tecnologies en la lectura","Les seues investigacions tenen reconeixement internacional","Finalment, contribueix al desenvolupament d''aquest camp d''estudi"]'),
('valenciano', 'eso', '{4}', '["La literatura autobiogràfica ha guanyat importància en les darreres dècades","Molts autors exploren la pròpia experiència vital com a matèria literària","Els seus textos oscil·len entre el record personal i la reflexió general","Aquestes obres mostren una gran sinceritat i profunditat emocional","Finalment, aporten noves perspectives sobre la societat valenciana actual"]'),
('valenciano', 'eso', '{4}', '["Per a estudiar l''estil d''un autor, comparem diverses obres seues","Primer, identifiquem els trets lingüístics recurrents en els seus textos","Després, analitzem els temes que apareixen amb més freqüència","A continuació, observem les estructures narratives preferides","Finalment, arribem a conclusions sobre el seu estil personal distintiu"]'),
('valenciano', 'eso', '{4}', '["El microrelat és''un gènere que ha guanyat popularitat recentment","Consisteix en contes molt breus amb una gran intensitat narrativa","Els autors valencians han explorat aquest gènere amb resultats interessants","Les noves tecnologies afavoreixen la difusió d''aquests textos breus","Finalment, representa una forma literària plenament vigent i viva"]'),
('valenciano', 'eso', '{4}', '["Per a comentar el registre lingüístic d''un text, analitzem diversos aspectes","Primer, identifiquem si és''un registre formal o informal","Després, observem el vocabulari i les expressions característiques utilitzades","A continuació, analitzem la sintaxi i el nivell de correcció lingüística","Finalment, relacionem el registre amb la intenció comunicativa del text"]'),
('valenciano', 'eso', '{4}', '["Silvestre Vilaplana és''un autor valencià especialitzat en novel·la històrica","Les seues obres recreen episodis importants de la història valenciana","Fa una investigació rigorosa abans de començar a escriure les seues novel·les","Els seus llibres han aconseguit una gran popularitat entre els lectors","Finalment, és''un dels autors més llegits actualment en valencià"]'),
('valenciano', 'eso', '{4}', '["La traducció al valencià d''obres internacionals és molt important","Permet accedir a la literatura universal en la nostra llengua","Les editorials publiquen obres clàssiques i contemporànies traduïdes","Els traductors fan una tasca meritòria amb gran professionalitat","Finalment, la traducció enriqueix el panorama cultural valencià"]'),
('valenciano', 'eso', '{4}', '["Per a concloure un comentari de text, sintetitzem les idees principals","Primer, recordem els aspectes més rellevants de l''anàlisi feta","Després, valorem la importància del text dins de l''obra i l''època","A continuació, oferim una interpretació global del text","Finalment, incloem una opinió personal fonamentada sobre l''obra"]'),
('valenciano', 'eso', '{4}', '["El futur de la literatura valenciana depèn de molts factors interconnectats","Necessita lectors compromesos que comprin i gaudeixen dels llibres","També requereix el suport institucional per a promoure la seua difusió","Els escriptors han de continuar creant obres de qualitat","Finalment, tots plegats som responsables del seu desenvolupament"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('robotica', 'eso', '{1}', '["La palabra robot proviene del checo robota que significa trabajo forzado","Fue usada por primera vez en una obra de teatro de mil novecientos veinte","El autor Karel Capek imaginó máquinas que realizaban tareas humanas","Desde entonces, el término se popularizó en todo el mundo","Finalmente, hoy designa cualquier máquina programable que ejecuta tareas automáticamente"]'),
('robotica', 'eso', '{1}', '["Para encender un LED con una placa Arduino, seguimos varios pasos sencillos","Primero, conectamos el LED a un pin digital mediante una resistencia","Después, escribimos el código para configurar el pin como salida","A continuación, subimos el programa a la placa mediante el cable USB","Finalmente, observamos cómo el LED se enciende y se apaga correctamente"]'),
('robotica', 'eso', '{1}', '["La robótica educativa ayuda a los estudiantes a aprender muchas materias","Primero, desarrolla el pensamiento lógico y la resolución de problemas","Después, fomenta la creatividad al diseñar nuevos proyectos originales","A continuación, enseña conceptos de electricidad, programación''y mecánica","Finalmente, prepara a los jóvenes para el mundo tecnológico del futuro"]'),
('robotica', 'eso', '{1}', '["Un circuito eléctrico simple está formado por varios componentes básicos","En primer lugar, necesita una fuente de energía como una pila","En segundo lugar, los cables conducen la corriente eléctrica al componente","Además, un interruptor permite abrir o cerrar el circuito","Finalmente, la bombilla o LED indica el paso de la corriente"]'),
('robotica', 'eso', '{1}', '["Para construir un robot sencillo, necesitamos varios componentes básicos","Primero, elegimos un chasis donde montar todas las piezas del robot","Después, instalamos dos motores con sus ruedas para el movimiento","A continuación, añadimos una placa de control y sensores","Finalmente, conectamos una batería para proporcionar energía eléctrica al conjunto"]'),
('robotica', 'eso', '{1}', '["Los robots domésticos se están''haciendo cada vez más populares en los hogares","Primero, encontramos robots aspiradores que limpian automáticamente el suelo","Después, existen robots que cortan el césped del jardín","A continuación, hay robots cocineros que preparan comidas sencillas","Finalmente, el futuro nos traerá robots cada vez más útiles para la casa"]'),
('robotica', 'eso', '{1}', '["Para programar un robot por primera vez, utilizamos un lenguaje sencillo","Empezamos con entornos gráficos como Scratch que usan bloques de colores","Después, aprendemos a combinar estos bloques formando pequeños programas","A continuación, probamos los programas en el robot para ver el resultado","Finalmente, podemos pasar a lenguajes de texto cuando tengamos más''experiencia"]'),
('robotica', 'eso', '{1}', '["Los sensores permiten a los robots percibir el mundo que los rodea","En primer lugar, los sensores de luz detectan cambios en la iluminación","En segundo lugar, los sensores de sonido captan ruidos del ambiente","Además, los sensores de temperatura miden el calor del entorno","Finalmente, toda esta información llega al cerebro del robot"]'),
('robotica', 'eso', '{1}', '["Para entender cómo funciona un motor eléctrico, analizamos sus partes","Primero, una bobina de cobre se encuentra dentro de un imán permanente","Después, cuando pasa corriente por la bobina aparece un campo magnético","A continuación, este campo interactúa con el imán provocando un giro","Finalmente, este movimiento giratorio se transmite al eje del motor"]'),
('robotica', 'eso', '{1}', '["La historia de los robots industriales comenzó en los años sesenta","Primero, el brazo Unimate se instaló en una fábrica de coches","Después, otras empresas siguieron su ejemplo automatizando más tareas","A continuación, los robots se hicieron cada vez más precisos y rápidos","Finalmente, hoy son imprescindibles en la fabricación moderna de productos"]'),
('robotica', 'eso', '{1}', '["Para que un robot reconozca un obstáculo, utiliza sensores de distancia","Primero, el sensor emite una onda de ultrasonidos hacia el frente","Después, la onda rebota en el obstáculo y vuelve al sensor","A continuación, el controlador calcula el tiempo de ida y vuelta","Finalmente, a partir del tiempo determina la distancia exacta al obstáculo"]'),
('robotica', 'eso', '{1}', '["La diferencia entre un robot y una máquina normal es la programación","Primero, una máquina normal hace siempre lo mismo de forma fija","Después, un robot puede ser programado para hacer diferentes tareas","A continuación, el robot puede adaptarse a situaciones cambiantes","Finalmente, esta flexibilidad es la característica principal de un robot"]'),
('robotica', 'eso', '{1}', '["Para evitar cortocircuitos cuando montamos un circuito, seguimos reglas básicas","Primero, comprobamos que los cables no tengan ninguna parte pelada","Después, verificamos que la polaridad de la batería sea la correcta","A continuación, usamos resistencias para proteger los componentes sensibles","Finalmente, revisamos todo el circuito antes de conectar la alimentación"]'),
('robotica', 'eso', '{1}', '["Los robots humanoides son aquellos con forma parecida a las personas","Primero, tienen dos brazos, dos piernas y una cabeza","Después, pueden caminar y realizar gestos similares a los humanos","A continuación, algunos incluso son capaces de reconocer caras y voces","Finalmente, representan uno de los grandes retos de la robótica actual"]'),
('robotica', 'eso', '{1}', '["Para medir la temperatura con un sensor, seguimos un proceso sencillo","Primero, conectamos el sensor a un pin analógico de Arduino","Después, el sensor genera un voltaje que depende de la temperatura","A continuación, el código lee este valor y lo convierte en grados","Finalmente, mostramos la temperatura en una pantalla o la guardamos"]'),
('robotica', 'eso', '{1}', '["La protoboard es una herramienta fundamental para hacer prototipos rápidos","Primero, permite conectar componentes sin necesidad de soldarlos","Después, tiene filas y columnas con conexiones internas ya realizadas","A continuación, podemos montar y desmontar el circuito las veces que queramos","Finalmente, es ideal para experimentar y aprender electrónica básica"]'),
('robotica', 'eso', '{1}', '["Para programar un bucle en un robot, utilizamos una instrucción''especial","Primero, escribimos la condición que debe cumplirse para repetir","Después, definimos las acciones que se ejecutarán''en cada iteración","A continuación, el programa verifica si la condición sigue siendo verdadera","Finalmente, si la condición se cumple, repite las instrucciones del bucle"]'),
('robotica', 'eso', '{1}', '["Los drones son robots voladores que se han popularizado en los últimos años","Primero, utilizan varios rotores para generar el empuje necesario","Después, llevan sensores que les ayudan a mantener el equilibrio","A continuación, pueden llevar cámaras para grabar desde el aire","Finalmente, se usan en muchos campos como el cine o la agricultura"]'),
('robotica', 'eso', '{1}', '["Para conectar un servomotor a un Arduino, necesitamos tres cables","Primero, el cable rojo va conectado a la alimentación de cinco voltios","Después, el cable negro se conecta a la tierra del circuito","A continuación, el cable de señal se conecta a un pin digital","Finalmente, usamos una librería para controlar el ángulo del servo"]'),
('robotica', 'eso', '{1}', '["La inteligencia artificial está cambiando la forma en que los robots actúan","Primero, les permite aprender de la experiencia como hacemos los humanos","Después, pueden reconocer imágenes, sonidos y hasta entender el lenguaje","A continuación, son capaces de tomar decisiones en situaciones nuevas","Finalmente, esta tecnología abre un mundo de posibilidades futuras"]'),
('robotica', 'eso', '{1}', '["Para hacer que un robot se mueva en línea recta, controlamos los motores","Primero, aseguramos que ambos motores giren a la misma velocidad","Después, el robot avanza sin desviarse hacia ningún lado","A continuación, si un motor va más rápido, el robot girará","Finalmente, necesitamos calibrar los motores para conseguir un movimiento preciso"]'),
('robotica', 'eso', '{1}', '["Los brazos robóticos industriales tienen varias articulaciones móviles","Primero, la base permite girar todo el brazo sobre sí mismo","Después, el hombro y el codo dan mayor alcance al brazo","A continuación, la muñeca orienta la herramienta en el ángulo correcto","Finalmente, la herramienta final realiza la tarea programada concreta"]'),
('robotica', 'eso', '{1}', '["Para que un robot siga una línea negra, usa sensores infrarrojos","Primero, los sensores se colocan debajo del robot apuntando al suelo","Después, cuando ven la línea negra, envían una señal al controlador","A continuación, el controlador activa los motores según la señal recibida","Finalmente, el robot avanza siguiendo exactamente el trazado de la línea"]'),
('robotica', 'eso', '{1}', '["Las leyes de la robótica fueron inventadas por el escritor Isaac Asimov","Primero, un robot no debe dañar a un ser humano","Después, debe obedecer las órdenes dadas por los humanos","A continuación, debe protegerse mientras no rompa las leyes anteriores","Finalmente, estas reglas son una referencia ética para la robótica moderna"]'),
('robotica', 'eso', '{1}', '["Para encender un motor con Arduino, necesitamos un circuito auxiliar especial","Primero, usamos un transistor o un driver como puente H","Después, conectamos el motor a una fuente de alimentación''adecuada","A continuación, el Arduino controla el transistor desde un pin digital","Finalmente, al activar el pin, el motor empieza a girar correctamente"]'),
('robotica', 'eso', '{1}', '["Los robots submarinos exploran las profundidades del océano inaccesibles","Primero, soportan enormes presiones gracias a su diseño resistente","Después, llevan cámaras y sensores para estudiar la vida marina","A continuación, se comunican con la superficie mediante cables especiales","Finalmente, nos ayudan a conocer mejor los misterios del fondo marino"]'),
('robotica', 'eso', '{1}', '["Para que un robot tome decisiones, usamos estructuras condicionales en el código","Primero, el robot lee el valor de un sensor determinado","Después, compara ese valor con una referencia programada","A continuación, si la condición''es verdadera ejecuta unas acciones","Finalmente, si es falsa ejecuta otras acciones alternativas programadas"]'),
('robotica', 'eso', '{1}', '["El proceso de diseño de un robot sigue varias fases importantes","Primero, identificamos qué problema queremos resolver con el robot","Después, diseñamos el chasis y elegimos los componentes adecuados","A continuación, montamos el hardware y programamos el software","Finalmente, probamos el robot y corregimos los errores encontrados"]'),
('robotica', 'eso', '{1}', '["Los sensores de ultrasonidos se inspiran en la forma en que los murciélagos cazan","Primero, el murciélago emite sonidos de alta frecuencia al volar","Después, estos sonidos rebotan en los objetos o insectos cercanos","A continuación, el murciélago percibe el eco con sus oídos","Finalmente, su cerebro calcula la posición''exacta de su presa"]'),
('robotica', 'eso', '{1}', '["Para instalar el software de Arduino, seguimos unos pasos sencillos","Primero, descargamos el programa desde la página web oficial","Después, ejecutamos el instalador y seguimos las indicaciones de pantalla","A continuación, conectamos la placa mediante el cable USB al ordenador","Finalmente, abrimos el entorno y empezamos a escribir nuestro primer programa"]'),
('robotica', 'eso', '{1}', '["Los robots de competición son construidos por estudiantes en todo el mundo","Primero, los equipos diseñan y montan su propio robot siguiendo unas reglas","Después, programan el robot para que cumpla con los desafíos del torneo","A continuación, se enfrentan a otros equipos en una competición''amistosa","Finalmente, los mejores equipos ganan premios y reconocimiento internacional"]'),
('robotica', 'eso', '{1}', '["Para clasificar objetos por color, un robot necesita un sensor especial","Primero, el sensor ilumina el objeto con una luz blanca","Después, mide cuánta luz roja, verde y azul refleja el objeto","A continuación, el programa compara estos valores con colores de referencia","Finalmente, el robot identifica el color y actúa en consecuencia"]'),
('robotica', 'eso', '{1}', '["Los robots médicos están cambiando la forma en que se realizan operaciones","Primero, los cirujanos controlan el robot desde una consola especial","Después, los brazos robóticos realizan movimientos muy precisos y pequeños","A continuación, esto permite operaciones menos invasivas para el paciente","Finalmente, la recuperación del paciente es más rápida con esta técnica"]'),
('robotica', 'eso', '{1}', '["Para proteger un circuito de daños, usamos elementos de seguridad","Primero, una resistencia limita el paso de corriente a los componentes","Después, un fusible se funde si pasa demasiada corriente por el circuito","A continuación, un diodo evita que la corriente circule en sentido contrario","Finalmente, estos elementos salvan los circuitos de posibles averías"]'),
('robotica', 'eso', '{1}', '["Los primeros robots de la historia eran muy diferentes a los actuales","Primero, eran máquinas grandes y pesadas con movimientos limitados","Después, solo podían repetir tareas simples una y otra vez","A continuación, con el tiempo se volvieron más precisos y versátiles","Finalmente, hoy los robots son inteligentes gracias a los avances tecnológicos"]'),
('robotica', 'eso', '{1}', '["Para hacer que un robot emita sonidos, conectamos un zumbador","Primero, el zumbador se conecta a un pin digital con una resistencia","Después, en el código activamos el pin con una frecuencia determinada","A continuación, el zumbador vibra produciendo un sonido audible","Finalmente, podemos cambiar las frecuencias para crear melodías sencillas"]'),
('robotica', 'eso', '{1}', '["Los materiales para construir un robot dependen del uso que le daremos","Primero, el plástico es ligero y barato pero menos resistente","Después, el metal proporciona robustez pero añade peso al robot","A continuación, la madera es fácil de trabajar y económica","Finalmente, cada material tiene sus ventajas y desventajas a considerar"]'),
('robotica', 'eso', '{1}', '["Para depurar un programa con errores, seguimos una metodología ordenada","Primero, leemos el mensaje de error que aparece en la pantalla","Después, localizamos la línea del programa donde está el problema","A continuación, analizamos si hay errores de sintaxis o de lógica","Finalmente, corregimos el código y volvemos a probar el programa"]'),
('robotica', 'eso', '{1}', '["La robótica educativa se imparte en muchos centros escolares actualmente","Primero, los alumnos aprenden conceptos teóricos sobre electrónica y programación","Después, realizan proyectos prácticos construyendo sus propios robots","A continuación, participan en concursos y ferias de robótica","Finalmente, desarrollan habilidades valiosas para su futuro profesional"]'),
('robotica', 'eso', '{1}', '["Para comunicar dos robots entre sí, necesitamos un sistema inalámbrico","Primero, cada robot debe llevar un módulo de comunicación Bluetooth","Después, uno de los robots actúa como maestro y el otro como esclavo","A continuación, establecen una conexión''y pueden intercambiar datos","Finalmente, este sistema permite coordinar las acciones entre varios robots"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('robotica', 'eso', '{2}', '["Para construir un sistema de riego automático, necesitamos varios componentes","Primero, un sensor de humedad mide la cantidad de agua en la tierra","Después, el Arduino lee este valor y decide si hay que regar","A continuación, si el valor es bajo activa una bomba de agua","Finalmente, la bomba riega hasta que el sensor detecta humedad suficiente"]'),
('robotica', 'eso', '{2}', '["El funcionamiento de un semáforo controlado por Arduino es sencillo de implementar","Primero, conectamos tres LEDs de colores verde, amarillo y rojo","Después, programamos una secuencia de encendido con tiempos concretos","A continuación, subimos el código a la placa para probarlo","Finalmente, los LEDs se encienden automáticamente imitando un semáforo real"]'),
('robotica', 'eso', '{2}', '["Las variables en programación sirven para almacenar datos dentro del código","Primero, las variables enteras guardan números sin decimales","Después, las variables flotantes almacenan números con decimales","A continuación, las booleanas contienen valores verdaderos o falsos","Finalmente, el tipo correcto depende del dato que queramos almacenar"]'),
('robotica', 'eso', '{2}', '["Para automatizar la apertura de una puerta, utilizamos varios elementos","Primero, un sensor detecta cuando alguien se acerca a la entrada","Después, el controlador procesa la señal y activa un motor","A continuación, el motor mueve la puerta hasta dejarla abierta","Finalmente, tras unos segundos cierra automáticamente la puerta"]'),
('robotica', 'eso', '{2}', '["Un sensor de humedad funciona midiendo la conductividad del suelo","Primero, dos electrodos se introducen en la tierra del cultivo","Después, pasa una pequeña corriente entre los dos electrodos","A continuación, cuanto más''húmeda es la tierra más corriente pasa","Finalmente, el Arduino convierte esta corriente en un valor de humedad"]'),
('robotica', 'eso', '{2}', '["Para que un robot reaccione ante la luz, usamos una fotorresistencia","Primero, conectamos la fotorresistencia al pin analógico A cero","Después, el código lee los valores que van de cero a mil veintitrés","A continuación, según''el valor el robot decide encender los faros","Finalmente, este sistema imita el funcionamiento de las farolas automáticas"]'),
('robotica', 'eso', '{2}', '["Las funciones en programación nos permiten reutilizar código en varios sitios","Primero, definimos la función con un nombre y unos parámetros","Después, escribimos el código que debe ejecutar esa función","A continuación, llamamos a la función cuando la necesitemos en el programa","Finalmente, esto hace el código más''ordenado y fácil de entender"]'),
('robotica', 'eso', '{2}', '["Para montar un robot seguidor de luz, necesitamos dos fotorresistencias","Primero, colocamos una fotorresistencia a cada lado del robot","Después, el programa compara los valores leídos por ambas","A continuación, si un lado recibe más luz el robot gira hacia él","Finalmente, el robot se mueve siempre hacia la fuente de luz más potente"]'),
('robotica', 'eso', '{2}', '["La función map de Arduino sirve para convertir valores de un rango a otro","Primero, tomamos el valor original del sensor o entrada","Después, indicamos el rango mínimo y máximo de entrada","A continuación, definimos el rango mínimo y máximo de salida deseado","Finalmente, la función devuelve el valor transformado al nuevo rango"]'),
('robotica', 'eso', '{2}', '["Para controlar un motor paso a paso, seguimos una secuencia concreta","Primero, identificamos los cables de las bobinas del motor","Después, los conectamos a un driver específico para motores paso a paso","A continuación, enviamos pulsos desde el Arduino al driver","Finalmente, el motor gira un ángulo exacto por cada pulso recibido"]'),
('robotica', 'eso', '{2}', '["Los interruptores de final de carrera son sensores mecánicos muy útiles","Primero, detectan cuando una pieza llega a un determinado punto","Después, al pulsarse envían una señal digital al controlador","A continuación, el programa puede parar el movimiento de seguridad","Finalmente, son esenciales en impresoras tres D''y máquinas CNC"]'),
('robotica', 'eso', '{2}', '["Para crear una alarma con Arduino, necesitamos un sensor y un actuador","Primero, un sensor PIR detecta el movimiento de personas en la habitación","Después, el Arduino procesa la señal del sensor de movimiento","A continuación, activa un zumbador para emitir un sonido fuerte","Finalmente, también puede enviar un mensaje al teléfono móvil del usuario"]'),
('robotica', 'eso', '{2}', '["Las resistencias pull up y pull down son importantes para los botones","Primero, evitan que las entradas digitales queden en un estado indefinido","Después, aseguran un valor claro cuando el botón no está pulsado","A continuación, permiten una lectura correcta del estado del botón","Finalmente, Arduino tiene resistencias pull up internas que podemos activar"]'),
('robotica', 'eso', '{2}', '["Para hacer un robot evitador de obstáculos, necesitamos varios componentes","Primero, montamos el chasis con dos motores y una batería","Después, colocamos un sensor de ultrasonidos en la parte frontal","A continuación, programamos al robot para que gire al detectar obstáculos","Finalmente, el robot se mueve libremente sin chocar contra nada"]'),
('robotica', 'eso', '{2}', '["El protocolo I2C permite conectar varios dispositivos con pocos cables","Primero, todos los dispositivos comparten dos cables de datos y reloj","Después, cada dispositivo tiene una dirección única para identificarlo","A continuación, el Arduino puede comunicarse con todos por turnos","Finalmente, este sistema es muy útil en proyectos con muchos sensores"]'),
('robotica', 'eso', '{2}', '["Para mostrar texto en una pantalla LCD, seguimos varios pasos ordenados","Primero, conectamos la pantalla a los pines del Arduino correctamente","Después, incluimos la librería LiquidCrystal en el código del programa","A continuación, inicializamos la pantalla con sus dimensiones concretas","Finalmente, usamos la función print para mostrar el texto deseado"]'),
('robotica', 'eso', '{2}', '["Los arrays en programación nos permiten almacenar varios datos juntos","Primero, declaramos el array con un tipo y un tamaño determinado","Después, asignamos valores a cada posición del array","A continuación, accedemos a cada valor usando su índice numérico","Finalmente, los arrays simplifican el manejo de conjuntos de datos"]'),
('robotica', 'eso', '{2}', '["Para fabricar un termómetro digital, necesitamos un sensor y una pantalla","Primero, conectamos un sensor de temperatura al pin analógico","Después, programamos la lectura periódica del sensor","A continuación, convertimos el valor leído a grados centígrados","Finalmente, mostramos la temperatura en una pantalla LCD"]'),
('robotica', 'eso', '{2}', '["Las interrupciones permiten al Arduino reaccionar rápidamente a eventos externos","Primero, configuramos un pin específico como entrada de interrupción","Después, asociamos una función''al evento que queramos detectar","A continuación, el Arduino continúa ejecutando el programa principal","Finalmente, cuando ocurre el evento, se ejecuta la función''asociada inmediatamente"]'),
('robotica', 'eso', '{2}', '["Para construir un contador de objetos, utilizamos un sensor específico","Primero, colocamos un sensor infrarrojo en el punto de paso","Después, cada vez que un objeto interrumpe el haz incrementamos un contador","A continuación, mostramos el valor del contador en una pantalla","Finalmente, el sistema cuenta automáticamente los objetos que pasan"]'),
('robotica', 'eso', '{2}', '["La comunicación serie permite enviar datos entre el Arduino y un ordenador","Primero, configuramos la velocidad de comunicación''en baudios","Después, usamos la función print para enviar datos al puerto serie","A continuación, abrimos el monitor serie en el ordenador","Finalmente, podemos ver los datos en tiempo real durante la ejecución"]'),
('robotica', 'eso', '{2}', '["Para crear un sistema de control remoto, usamos un mando infrarrojo","Primero, un sensor IR recibe las señales enviadas por el mando","Después, cada botón del mando emite un código único y reconocible","A continuación, el Arduino identifica el código y ejecuta una acción","Finalmente, podemos controlar el robot a distancia con el mando"]'),
('robotica', 'eso', '{2}', '["Los sensores de inclinación detectan cuando un objeto cambia su posición","Primero, contienen una pequeña bola o mercurio en su interior","Después, al inclinar el sensor la bola cambia de posición","A continuación, este cambio se traduce en una señal eléctrica","Finalmente, el Arduino puede detectar si el sensor está inclinado"]'),
('robotica', 'eso', '{2}', '["Para programar un temporizador con Arduino, usamos la función millis","Primero, esta función devuelve el tiempo desde que encendimos la placa","Después, guardamos el tiempo al inicio de un evento determinado","A continuación, calculamos la diferencia con el tiempo actual","Finalmente, cuando la diferencia supera un valor, ejecutamos una acción"]'),
('robotica', 'eso', '{2}', '["El puente H es un circuito que permite controlar el sentido de giro de un motor","Primero, consta de cuatro transistores que forman una letra H","Después, activando unos u otros transistores cambiamos el sentido","A continuación, el motor puede girar en ambas direcciones","Finalmente, este circuito es esencial para controlar motores de un robot móvil"]'),
('robotica', 'eso', '{2}', '["Para construir un detector de humo, combinamos varios componentes","Primero, usamos un sensor específico para detectar partículas de humo","Después, el Arduino lee el valor del sensor constantemente","A continuación, si el valor supera un umbral activa una alarma sonora","Finalmente, también puede enviar una señal a un sistema de extinción"]'),
('robotica', 'eso', '{2}', '["Las estructuras de control condicionales permiten tomar decisiones en el código","Primero, la instrucción''if verifica si una condición''es verdadera","Después, else ejecuta un código alternativo cuando la condición''es falsa","A continuación, podemos anidar varios if para decisiones más complejas","Finalmente, switch se usa cuando hay muchas opciones posibles a evaluar"]'),
('robotica', 'eso', '{2}', '["Para hacer un velocímetro con Arduino, necesitamos varios componentes","Primero, un sensor de efecto Hall detecta el paso de un imán","Después, contamos cuántos pulsos se generan en un segundo","A continuación, calculamos la velocidad a partir de la frecuencia","Finalmente, mostramos el resultado en una pantalla LCD"]'),
('robotica', 'eso', '{2}', '["El consumo de energía de un proyecto depende de todos sus componentes","Primero, calculamos la corriente que necesita cada componente del circuito","Después, sumamos todas las corrientes para obtener el total","A continuación, elegimos una batería con capacidad suficiente","Finalmente, esto asegura un funcionamiento prolongado del robot o sistema"]'),
('robotica', 'eso', '{2}', '["Para construir un robot sumo, los equipos siguen unas reglas específicas","Primero, el robot debe caber dentro de unas dimensiones máximas","Después, el peso no puede superar un límite establecido en el concurso","A continuación, el robot debe empujar al oponente fuera del dojo","Finalmente, gana quien consigue sacar al rival de la pista circular"]'),
('robotica', 'eso', '{2}', '["Los sensores capacitivos detectan objetos sin necesidad de contacto físico","Primero, generan un campo eléctrico alrededor del sensor","Después, cuando un objeto se acerca cambia la capacitancia","A continuación, el sensor detecta este cambio y envía una señal","Finalmente, se usan en pantallas táctiles y detectores de presencia"]'),
('robotica', 'eso', '{2}', '["Para crear un piano con Arduino, necesitamos botones y un zumbador","Primero, conectamos varios botones a pines digitales distintos","Después, asignamos una frecuencia diferente a cada botón","A continuación, cuando pulsamos un botón suena la nota correspondiente","Finalmente, podemos tocar melodías simples con nuestro piano casero"]'),
('robotica', 'eso', '{2}', '["El tiempo de respuesta de un sensor es un parámetro muy importante","Primero, indica cuánto tarda en detectar un cambio en su entorno","Después, un tiempo de respuesta corto es mejor para aplicaciones rápidas","A continuación, los sensores lentos pueden perder información''importante","Finalmente, elegir el sensor adecuado depende de la aplicación concreta"]'),
('robotica', 'eso', '{2}', '["Para fabricar una pulsera inteligente, combinamos varios elementos","Primero, un sensor de pulso mide el ritmo cardíaco del usuario","Después, un Arduino procesa los datos leídos periódicamente","A continuación, una pantalla muestra el valor del pulso obtenido","Finalmente, también puede enviar los datos a una aplicación móvil"]'),
('robotica', 'eso', '{2}', '["Las antenas son elementos fundamentales en los sistemas inalámbricos","Primero, transforman las señales eléctricas en ondas electromagnéticas","Después, estas ondas viajan por el aire hasta el receptor","A continuación, la antena receptora hace el proceso inverso","Finalmente, la comunicación''inalámbrica depende de la calidad de las antenas"]'),
('robotica', 'eso', '{2}', '["Para automatizar una persiana, necesitamos un motor y sensores","Primero, un sensor de luz mide la intensidad del sol exterior","Después, el Arduino decide si subir o bajar la persiana","A continuación, activa un motor conectado al eje de la persiana","Finalmente, la persiana se mueve automáticamente según la luz"]'),
('robotica', 'eso', '{2}', '["Los shields son placas que se acoplan encima del Arduino","Primero, añaden funcionalidades específicas como wifi o control de motores","Después, se conectan directamente sin necesidad de cables adicionales","A continuación, aprovechan todos los pines del Arduino de forma ordenada","Finalmente, simplifican la construcción de proyectos más complejos"]'),
('robotica', 'eso', '{2}', '["Para programar una luz nocturna automática, usamos un sensor y un LED","Primero, medimos la luz ambiental con una fotorresistencia","Después, cuando la luz baja de un umbral encendemos el LED","A continuación, cuando la luz sube apagamos el LED automáticamente","Finalmente, tenemos una luz nocturna que funciona sin intervención''humana"]'),
('robotica', 'eso', '{2}', '["El código binario es el lenguaje que entienden todos los ordenadores","Primero, solo utiliza dos valores posibles que son cero y uno","Después, estos valores representan los estados apagado y encendido","A continuación, cualquier información se puede codificar en binario","Finalmente, los microcontroladores trabajan internamente con este sistema"]'),
('robotica', 'eso', '{2}', '["Para construir un cronómetro digital, combinamos varios elementos","Primero, utilizamos un botón para iniciar y parar el cronómetro","Después, usamos la función millis para medir el tiempo transcurrido","A continuación, calculamos minutos, segundos y centésimas a partir de milisegundos","Finalmente, mostramos el tiempo en una pantalla LCD actualizada"]'),
('robotica', 'eso', '{2}', '["La memoria de un microcontrolador está dividida en varias partes","Primero, la memoria flash almacena el programa que se va a ejecutar","Después, la memoria RAM guarda las variables durante la ejecución","A continuación, la EEPROM guarda datos que no se borran al apagar","Finalmente, cada tipo tiene un uso específico en los proyectos"]'),
('robotica', 'eso', '{2}', '["Para construir un robot limpiador sencillo, necesitamos varios componentes","Primero, montamos un chasis con ruedas y dos motores","Después, añadimos un pequeño cepillo en la parte delantera","A continuación, programamos al robot para que se mueva de forma aleatoria","Finalmente, el robot limpia el suelo mientras se desplaza por la habitación"]'),
('robotica', 'eso', '{2}', '["Los transistores son componentes electrónicos con múltiples usos","Primero, pueden actuar como interruptores controlados eléctricamente","Después, también pueden amplificar señales pequeñas de entrada","A continuación, son la base de todos los circuitos integrados modernos","Finalmente, sin ellos no existirían los ordenadores actuales"]'),
('robotica', 'eso', '{2}', '["Para construir un simulador de tráfico, usamos varios LEDs y Arduino","Primero, conectamos seis LEDs formando dos semáforos coordinados","Después, programamos la secuencia de cambio para ambos semáforos","A continuación, añadimos un sensor para detectar peatones","Finalmente, cuando un peatón quiere cruzar los semáforos cambian automáticamente"]'),
('robotica', 'eso', '{2}', '["Las placas clónicas de Arduino ofrecen las mismas funciones a menor precio","Primero, son compatibles con el software oficial de Arduino","Después, tienen los mismos componentes que las placas originales","A continuación, permiten empezar en la robótica sin gran inversión","Finalmente, son ideales para estudiantes y aficionados a la electrónica"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('robotica', 'eso', '{3}', '["Para implementar el control PWM en un motor, seguimos unos pasos concretos","Primero, configuramos un pin digital como salida PWM del Arduino","Después, utilizamos la función''analogWrite para enviar la señal al motor","A continuación, el valor entre cero y doscientos cincuenta y cinco determina la velocidad","Finalmente, podemos variar la velocidad del motor de forma suave y precisa"]'),
('robotica', 'eso', '{3}', '["La visión''artificial permite a los robots interpretar imágenes del entorno","Primero, una cámara captura imágenes del mundo exterior constantemente","Después, un software procesa cada imagen buscando patrones específicos","A continuación, algoritmos avanzados identifican objetos, caras o colores","Finalmente, el robot toma decisiones basándose en lo que ha visto"]'),
('robotica', 'eso', '{3}', '["Para programar un robot con máquinas de estados, definimos los estados posibles","Primero, identificamos los distintos comportamientos que puede tener el robot","Después, establecemos las condiciones para cambiar entre los estados","A continuación, implementamos cada estado como una función''en el código","Finalmente, el programa principal gestiona las transiciones entre estados"]'),
('robotica', 'eso', '{3}', '["Los giroscopios son sensores que miden la velocidad angular de rotación","Primero, utilizan el principio de conservación del momento angular","Después, detectan los cambios de orientación del dispositivo donde están","A continuación, el Arduino procesa los datos mediante una librería específica","Finalmente, son esenciales para drones, móviles y robots que necesitan estabilidad"]'),
('robotica', 'eso', '{3}', '["Para construir un brazo robótico educativo, seguimos un proceso ordenado","Primero, diseñamos la estructura con varias articulaciones movidas por servos","Después, montamos las piezas ensamblándolas en el orden correcto","A continuación, programamos cada servo para que se mueva al ángulo deseado","Finalmente, coordinamos todos los movimientos para realizar tareas complejas"]'),
('robotica', 'eso', '{3}', '["La programación''orientada a objetos organiza el código de forma estructurada","Primero, definimos clases que representan elementos del mundo real","Después, creamos objetos que son instancias concretas de esas clases","A continuación, cada objeto tiene sus propiedades y sus métodos","Finalmente, esto facilita el mantenimiento y la reutilización del código"]'),
('robotica', 'eso', '{3}', '["Para diseñar el chasis de un robot, usamos programas de modelado tres D","Primero, medimos todos los componentes que queremos montar en el chasis","Después, dibujamos el diseño en el ordenador con las medidas exactas","A continuación, imprimimos las piezas en una impresora tres D","Finalmente, ensamblamos las piezas y montamos el robot completo"]'),
('robotica', 'eso', '{3}', '["Los sensores LIDAR miden distancias con gran precisión''usando láser","Primero, emiten un haz de luz láser hacia el entorno","Después, este haz rebota en los objetos cercanos y vuelve","A continuación, el sensor mide el tiempo de ida y vuelta","Finalmente, con esta información crea un mapa tridimensional del entorno"]'),
('robotica', 'eso', '{3}', '["Para implementar un sistema de telemetría, combinamos varios componentes electrónicos","Primero, sensores recogen datos del robot como velocidad y temperatura","Después, un microcontrolador procesa y organiza los datos leídos","A continuación, un módulo inalámbrico envía los datos a un ordenador","Finalmente, el ordenador muestra gráficas en tiempo real para el análisis"]'),
('robotica', 'eso', '{3}', '["El protocolo SPI permite la comunicación rápida entre varios dispositivos","Primero, necesita cuatro cables para funcionar correctamente entre dispositivos","Después, un dispositivo maestro controla la comunicación con los esclavos","A continuación, los datos se transmiten de forma síncrona por el reloj","Finalmente, es más rápido que el protocolo I dos C pero usa más cables"]'),
('robotica', 'eso', '{3}', '["Para crear un sistema de reconocimiento de voz, usamos módulos específicos","Primero, un módulo graba las palabras que queremos reconocer","Después, las palabras se procesan extrayendo sus características principales","A continuación, el Arduino compara las palabras nuevas con las almacenadas","Finalmente, ejecuta la acción''asociada a la palabra reconocida"]'),
('robotica', 'eso', '{3}', '["Los acelerómetros detectan aceleraciones en los tres ejes del espacio","Primero, contienen una pequeña masa que se desplaza con la aceleración","Después, este desplazamiento genera una señal eléctrica proporcional","A continuación, el microcontrolador lee los valores en cada eje","Finalmente, podemos detectar inclinaciones, vibraciones y movimientos bruscos"]'),
('robotica', 'eso', '{3}', '["Para construir un dron casero, necesitamos varios componentes específicos","Primero, un controlador de vuelo con sensores inerciales integrados","Después, cuatro motores con sus hélices y variadores de velocidad","A continuación, un marco ligero pero resistente para sostener todo","Finalmente, un sistema de control remoto para pilotar el dron"]'),
('robotica', 'eso', '{3}', '["El algoritmo A estrella se usa en robótica para encontrar el camino óptimo","Primero, el robot tiene un mapa del entorno con obstáculos conocidos","Después, el algoritmo evalúa diferentes rutas posibles hacia el destino","A continuación, calcula el coste de cada ruta teniendo en cuenta la distancia","Finalmente, elige la ruta con el menor coste total"]'),
('robotica', 'eso', '{3}', '["Para procesar imágenes en Arduino, necesitamos una placa más potente","Primero, conectamos una cámara compatible a la placa principal","Después, usamos librerías especializadas en procesamiento de imágenes","A continuación, aplicamos filtros para simplificar la imagen capturada","Finalmente, detectamos bordes, colores o formas de los objetos"]'),
('robotica', 'eso', '{3}', '["Los encoders son sensores que miden la rotación de un motor","Primero, generan pulsos eléctricos cuando el eje del motor gira","Después, el Arduino cuenta estos pulsos para calcular el ángulo girado","A continuación, también puede calcular la velocidad de rotación","Finalmente, son esenciales para el control preciso de los motores"]'),
('robotica', 'eso', '{3}', '["Para implementar un control de posición, usamos un bucle de realimentación","Primero, medimos la posición''actual del elemento con un sensor","Después, calculamos el error entre la posición''actual y la deseada","A continuación, enviamos una corrección''al motor proporcional al error","Finalmente, el sistema converge hacia la posición deseada con precisión"]'),
('robotica', 'eso', '{3}', '["Las impresoras tres D construyen objetos depositando material capa a capa","Primero, diseñamos el objeto en un programa de modelado en el ordenador","Después, el software laminador divide el modelo en capas finas horizontales","A continuación, la impresora deposita material siguiendo cada capa","Finalmente, obtenemos un objeto físico tras varias horas de impresión"]'),
('robotica', 'eso', '{3}', '["Para controlar un motor de corriente continua con precisión, usamos el PWM","Primero, generamos una señal con un ciclo de trabajo variable","Después, un driver amplifica la señal al nivel del motor","A continuación, el motor recibe energía intermitente proporcional al ciclo","Finalmente, la velocidad del motor se ajusta con gran precisión"]'),
('robotica', 'eso', '{3}', '["Los sensores de efecto Hall detectan la presencia de campos magnéticos","Primero, contienen un material semiconductor sensible al magnetismo","Después, cuando un imán se acerca generan una pequeña tensión","A continuación, el Arduino puede detectar esta señal fácilmente","Finalmente, se usan para contar revoluciones o detectar posiciones"]'),
('robotica', 'eso', '{3}', '["Para crear un sistema de seguimiento solar, combinamos sensores y motores","Primero, dos fotorresistencias detectan la posición del sol en el cielo","Después, el Arduino compara los valores de ambos sensores","A continuación, ordena al motor que gire los paneles hacia la luz","Finalmente, los paneles solares siguen al sol durante todo el día"]'),
('robotica', 'eso', '{3}', '["Los microcontroladores ESP treinta y dos tienen conectividad inalámbrica integrada","Primero, incorporan wifi y Bluetooth directamente en la placa","Después, permiten crear proyectos de Internet de las cosas fácilmente","A continuación, tienen más memoria y potencia que el Arduino clásico","Finalmente, son ideales para proyectos que requieren conexión''a internet"]'),
('robotica', 'eso', '{3}', '["Para implementar un filtro digital, procesamos las lecturas del sensor","Primero, guardamos varias lecturas recientes en un buffer circular","Después, calculamos el promedio de todas estas lecturas almacenadas","A continuación, usamos este valor promediado en lugar del valor directo","Finalmente, el ruido del sensor se reduce significativamente con este filtro"]'),
('robotica', 'eso', '{3}', '["La cinemática directa calcula la posición del extremo de un brazo robótico","Primero, conocemos los ángulos de todas las articulaciones del brazo","Después, aplicamos fórmulas trigonométricas con las longitudes de los eslabones","A continuación, obtenemos las coordenadas X, Y, Z del extremo","Finalmente, esta información permite saber dónde está la herramienta del robot"]'),
('robotica', 'eso', '{3}', '["Para construir un robot con Raspberry Pi, combinamos diversas capacidades","Primero, la Raspberry es un ordenador completo con sistema operativo","Después, podemos programarla en Python con muchas librerías disponibles","A continuación, conectamos cámaras, sensores y motores a sus pines","Finalmente, obtenemos robots más potentes capaces de tareas complejas"]'),
('robotica', 'eso', '{3}', '["Los algoritmos de seguimiento de línea avanzados usan el control PID","Primero, el sensor detecta la desviación respecto al centro de la línea","Después, el algoritmo calcula una corrección proporcional al error","A continuación, también tiene en cuenta la acumulación del error","Finalmente, el robot sigue la línea de forma muy suave y precisa"]'),
('robotica', 'eso', '{3}', '["Para medir distancias con precisión, los sensores de tiempo de vuelo son excelentes","Primero, emiten un pulso de luz láser hacia el objetivo","Después, miden el tiempo exacto que tarda la luz en volver","A continuación, calculan la distancia multiplicando por la velocidad de la luz","Finalmente, alcanzan precisiones de milímetros en sus mediciones"]'),
('robotica', 'eso', '{3}', '["El control en lazo cerrado es más preciso que el control en lazo abierto","Primero, en el lazo cerrado un sensor mide la variable a controlar","Después, el controlador compara la medición con el valor deseado","A continuación, aplica una corrección para reducir la diferencia","Finalmente, el sistema se autocorrige continuamente ante perturbaciones"]'),
('robotica', 'eso', '{3}', '["Para desarrollar una mano robótica, seguimos un proceso complejo","Primero, diseñamos cinco dedos articulados con varios grados de libertad","Después, cada dedo es accionado por un servo motor independiente","A continuación, programamos los movimientos para agarrar objetos","Finalmente, los sensores de presión''evitan romper los objetos delicados"]'),
('robotica', 'eso', '{3}', '["Los LEDs direccionables permiten crear efectos luminosos elaborados","Primero, cada LED tiene su propio chip de control integrado","Después, se conectan en cadena usando solo tres cables en total","A continuación, podemos controlar el color e intensidad de cada uno","Finalmente, son muy usados en proyectos decorativos y en pantallas"]'),
('robotica', 'eso', '{3}', '["Para programar una red neuronal sencilla en Arduino, usamos librerías","Primero, definimos la arquitectura con capas de entrada y salida","Después, entrenamos la red con ejemplos de datos conocidos","A continuación, ajustamos los pesos para minimizar el error","Finalmente, la red puede hacer predicciones con datos nuevos"]'),
('robotica', 'eso', '{3}', '["Los módulos de comunicación LoRa permiten enlaces de largo alcance","Primero, utilizan frecuencias bajas que penetran muchos obstáculos","Después, consumen muy poca energía comparados con otras tecnologías","A continuación, pueden transmitir datos a varios kilómetros de distancia","Finalmente, son ideales para monitorización''en zonas rurales"]'),
('robotica', 'eso', '{3}', '["Para integrar una base de datos en un proyecto de robótica, necesitamos un servidor","Primero, el robot envía datos de sus sensores a un servidor central","Después, el servidor almacena toda la información''en una base de datos","A continuación, podemos consultar los datos históricos en cualquier momento","Finalmente, esto permite analizar el comportamiento del robot a largo plazo"]'),
('robotica', 'eso', '{3}', '["El diseño asistido por ordenador facilita la creación de piezas mecánicas","Primero, dibujamos el boceto inicial en dos dimensiones","Después, añadimos cotas y restricciones geométricas al boceto","A continuación, extruimos o revolucionamos el boceto en tres dimensiones","Finalmente, obtenemos un modelo tres D listo para fabricar"]'),
('robotica', 'eso', '{3}', '["Para construir un robot autónomo, necesita sensores, procesamiento y actuadores","Primero, los sensores recogen información del entorno que rodea al robot","Después, la unidad de procesamiento analiza los datos y toma decisiones","A continuación, los actuadores ejecutan las acciones que decide el controlador","Finalmente, este ciclo se repite constantemente durante el funcionamiento"]'),
('robotica', 'eso', '{3}', '["Los motores brushless son más''eficientes que los motores con escobillas","Primero, no tienen partes mecánicas en contacto que se desgasten","Después, usan imanes permanentes y bobinas controladas electrónicamente","A continuación, necesitan un controlador electrónico específico para funcionar","Finalmente, se usan en drones, coches eléctricos y aplicaciones industriales"]'),
('robotica', 'eso', '{3}', '["Para automatizar un invernadero inteligente, combinamos varios sistemas","Primero, sensores miden temperatura, humedad y luz del interior","Después, un controlador central analiza todos los datos recibidos","A continuación, activa calefacción, ventilación''o riego según sea necesario","Finalmente, las plantas crecen en las condiciones óptimas automáticamente"]'),
('robotica', 'eso', '{3}', '["La seguridad en robótica es fundamental cuando hay personas cerca","Primero, los robots incorporan sensores para detectar personas alrededor","Después, reducen su velocidad o se detienen si detectan proximidad","A continuación, botones de emergencia permiten parar el robot al instante","Finalmente, estas medidas protegen tanto a usuarios como a los robots"]'),
('robotica', 'eso', '{3}', '["Para programar un dispositivo IoT, seguimos varios pasos específicos","Primero, el dispositivo se conecta a la red wifi local","Después, establece una conexión con un servidor en la nube","A continuación, envía los datos de sus sensores periódicamente","Finalmente, recibe comandos del servidor para controlar sus actuadores"]'),
('robotica', 'eso', '{3}', '["Los sistemas de navegación GPS son esenciales para robots exteriores","Primero, el receptor recibe señales de varios satélites en órbita","Después, calcula la distancia a cada satélite midiendo el tiempo","A continuación, triangula su posición''exacta en la superficie terrestre","Finalmente, el robot puede moverse autónomamente siguiendo rutas predefinidas"]'),
('robotica', 'eso', '{3}', '["Para modelar el comportamiento de un robot, usamos diagramas de flujo","Primero, representamos cada acción''o decisión con un símbolo específico","Después, conectamos los símbolos con flechas que muestran el flujo","A continuación, añadimos las condiciones en los puntos de decisión","Finalmente, el diagrama facilita la comprensión''y programación del robot"]'),
('robotica', 'eso', '{3}', '["Los reductores mecánicos aumentan el par de un motor reduciendo su velocidad","Primero, utilizan engranajes con diferentes tamaños conectados","Después, el motor gira rápido pero la salida gira lento","A continuación, la fuerza disponible en la salida es mucho mayor","Finalmente, son esenciales en robots que necesitan levantar pesos"]'),
('robotica', 'eso', '{3}', '["Para detectar obstáculos en tres dimensiones, los robots usan varios sensores","Primero, combinan información de ultrasonidos, infrarrojos y cámaras","Después, el software fusiona todos los datos para crear una percepción completa","A continuación, el robot identifica obstáculos en cualquier dirección","Finalmente, puede navegar con seguridad en entornos complejos"]'),
('robotica', 'eso', '{3}', '["El procesamiento en la nube permite realizar cálculos complejos remotamente","Primero, el robot envía los datos al servidor en la nube","Después, potentes ordenadores procesan los datos recibidos rápidamente","A continuación, devuelven los resultados al robot casi al instante","Finalmente, esto permite usar algoritmos avanzados en dispositivos pequeños"]'),
('robotica', 'eso', '{3}', '["Para crear un robot de enjambre, cada unidad sigue reglas sencillas","Primero, cada robot comunica su posición''a los robots cercanos","Después, ajusta su movimiento para mantener una formación definida","A continuación, el comportamiento global emerge de las interacciones locales","Finalmente, el enjambre puede realizar tareas que un solo robot no podría"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('robotica', 'eso', '{4}', '["Para entrenar un modelo de aprendizaje automático, necesitamos un conjunto de datos","Primero, recolectamos muchos ejemplos representativos del problema a resolver","Después, dividimos los datos en conjuntos de entrenamiento y validación","A continuación, elegimos un algoritmo apropiado y ajustamos sus parámetros","Finalmente, evaluamos el rendimiento del modelo con los datos de validación"]'),
('robotica', 'eso', '{4}', '["El aprendizaje profundo utiliza redes neuronales con muchas capas","Primero, estas redes se inspiran en el funcionamiento del cerebro humano","Después, cada capa extrae características cada vez más''abstractas de los datos","A continuación, el entrenamiento ajusta millones de parámetros en la red","Finalmente, consiguen reconocer patrones muy complejos en imágenes y sonidos"]'),
('robotica', 'eso', '{4}', '["Para desarrollar un proyecto final de robótica, seguimos una metodología ágil","Primero, definimos claramente los objetivos y los requisitos del proyecto","Después, dividimos el trabajo en tareas pequeñas y manejables","A continuación, construimos el prototipo de forma iterativa probando cada parte","Finalmente, integramos todos los subsistemas en una solución funcional"]'),
('robotica', 'eso', '{4}', '["Los coches autónomos combinan múltiples tecnologías avanzadas de forma integrada","Primero, usan cámaras y LIDAR para percibir el entorno en tiempo real","Después, algoritmos de inteligencia artificial interpretan esa información","A continuación, el sistema de planificación decide la trayectoria óptima","Finalmente, los actuadores controlan dirección, aceleración''y frenado con precisión"]'),
('robotica', 'eso', '{4}', '["Para crear una aplicación de control remoto para un robot, usamos varios pasos","Primero, diseñamos la interfaz gráfica con botones y controles intuitivos","Después, implementamos la comunicación''entre la app y el robot","A continuación, definimos los comandos que puede enviar la aplicación","Finalmente, probamos la aplicación con el robot real para ajustarla"]'),
('robotica', 'eso', '{4}', '["El procesamiento del lenguaje natural permite a los robots entender el habla humana","Primero, un micrófono captura el sonido de la voz del usuario","Después, se convierte el audio en texto mediante algoritmos específicos","A continuación, el sistema analiza el texto para entender su significado","Finalmente, el robot ejecuta la acción pedida por el usuario"]'),
('robotica', 'eso', '{4}', '["Para implementar el reconocimiento facial, usamos algoritmos entrenados previamente","Primero, una cámara captura la imagen del rostro de una persona","Después, el algoritmo extrae las características únicas de ese rostro","A continuación, compara esas características con una base de datos","Finalmente, identifica a la persona si coincide con algún registro"]'),
('robotica', 'eso', '{4}', '["Las redes neuronales convolucionales son especialistas en procesamiento de imágenes","Primero, aplican filtros para detectar bordes y formas básicas","Después, capas sucesivas combinan estas características en otras más complejas","A continuación, las últimas capas clasifican la imagen en categorías","Finalmente, pueden reconocer objetos, animales o escenas con gran precisión"]'),
('robotica', 'eso', '{4}', '["Para desplegar un proyecto IoT a gran escala, necesitamos una plataforma robusta","Primero, cada dispositivo se registra en un servidor central de gestión","Después, los dispositivos envían sus datos mediante protocolos como MQTT","A continuación, el servidor procesa y almacena toda la información","Finalmente, los usuarios acceden a los datos a través de aplicaciones web"]'),
('robotica', 'eso', '{4}', '["Los sistemas ciberfísicos integran elementos computacionales y físicos de forma coordinada","Primero, sensores capturan datos del mundo físico continuamente","Después, los datos se procesan en sistemas digitales para tomar decisiones","A continuación, los actuadores modifican el mundo físico según las decisiones","Finalmente, este bucle cerrado permite automatizar procesos complejos"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de recomendación, utilizamos algoritmos de aprendizaje","Primero, recogemos datos sobre las preferencias de los usuarios","Después, el sistema analiza patrones en los comportamientos pasados","A continuación, identifica similitudes entre usuarios con gustos parecidos","Finalmente, recomienda productos o contenidos basándose en esas similitudes"]'),
('robotica', 'eso', '{4}', '["La realidad aumentada combina elementos virtuales con el mundo real","Primero, una cámara captura imágenes del entorno del usuario","Después, el software analiza las imágenes para entender la escena","A continuación, superpone objetos virtuales en posiciones específicas","Finalmente, el usuario ve una combinación perfecta de elementos reales y virtuales"]'),
('robotica', 'eso', '{4}', '["Para construir un gemelo digital de un robot, creamos una réplica virtual","Primero, modelamos con precisión la geometría y las propiedades físicas","Después, sincronizamos el gemelo digital con el robot real mediante sensores","A continuación, podemos simular comportamientos antes de ejecutarlos","Finalmente, el gemelo digital permite optimizar y predecir problemas"]'),
('robotica', 'eso', '{4}', '["Los algoritmos genéticos se inspiran en la evolución biológica para optimizar problemas","Primero, generamos una población''inicial de soluciones aleatorias","Después, evaluamos cada solución según''una función''objetivo","A continuación, seleccionamos las mejores soluciones para reproducirlas","Finalmente, tras varias generaciones obtenemos una solución muy buena"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de vigilancia inteligente, combinamos varias tecnologías","Primero, cámaras capturan vídeo del área que queremos vigilar","Después, algoritmos de visión detectan movimientos inusuales o intrusos","A continuación, el sistema envía alertas cuando ocurre algo anómalo","Finalmente, los operarios pueden responder rápidamente a incidentes"]'),
('robotica', 'eso', '{4}', '["La robótica colaborativa permite que humanos y robots trabajen juntos de forma segura","Primero, los robots tienen sensores especiales para detectar personas","Después, reducen velocidad o se detienen cuando un humano está cerca","A continuación, pueden aprender de los movimientos de los operarios","Finalmente, combinan la precisión de las máquinas con la creatividad humana"]'),
('robotica', 'eso', '{4}', '["Para desarrollar una aplicación de chatbot, utilizamos procesamiento de lenguaje","Primero, definimos las preguntas y respuestas más frecuentes del sistema","Después, entrenamos un modelo con ejemplos de conversaciones reales","A continuación, el chatbot aprende a identificar las intenciones del usuario","Finalmente, responde de forma natural a preguntas variadas"]'),
('robotica', 'eso', '{4}', '["Los sensores biométricos identifican a las personas por características únicas","Primero, pueden usar la huella dactilar, el iris o la cara","Después, extraen patrones únicos de cada característica biométrica","A continuación, comparan estos patrones con una base de datos segura","Finalmente, se usan en sistemas de control de acceso y seguridad"]'),
('robotica', 'eso', '{4}', '["Para crear un sistema predictivo de mantenimiento, analizamos datos históricos","Primero, recogemos datos sobre el funcionamiento normal de las máquinas","Después, identificamos patrones que preceden a los fallos conocidos","A continuación, entrenamos un modelo para detectar esos patrones","Finalmente, el sistema predice fallos antes de que ocurran realmente"]'),
('robotica', 'eso', '{4}', '["La ética en robótica se ha convertido en un tema muy importante actualmente","Primero, debemos considerar el impacto de los robots en el empleo","Después, hay que pensar en la privacidad de los datos recogidos","A continuación, se debe asegurar la transparencia de los algoritmos","Finalmente, todos los actores implicados deben debatir estas cuestiones"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de tracking en tiempo real, necesitamos varios componentes","Primero, cada objeto lleva un dispositivo GPS con conexión móvil","Después, el dispositivo envía su posición''al servidor periódicamente","A continuación, el servidor almacena y procesa las posiciones recibidas","Finalmente, los usuarios ven la ubicación''actualizada en un mapa"]'),
('robotica', 'eso', '{4}', '["Los drones autónomos para agricultura de precisión realizan múltiples tareas","Primero, sobrevuelan los cultivos capturando imágenes multiespectrales","Después, analizan las imágenes para detectar problemas en las plantas","A continuación, generan mapas de tratamiento para aplicar productos","Finalmente, los agricultores solo tratan las zonas que realmente lo necesitan"]'),
('robotica', 'eso', '{4}', '["Para diseñar un robot bioinspirado, estudiamos primero a un animal real","Primero, analizamos cómo se mueve y funciona el animal elegido","Después, identificamos los principios biológicos más''interesantes para replicar","A continuación, traducimos estos principios a componentes mecánicos y electrónicos","Finalmente, construimos un robot que imita el comportamiento del animal"]'),
('robotica', 'eso', '{4}', '["El blockchain puede aplicarse a la robótica para mejorar la seguridad","Primero, cada acción del robot se registra como una transacción''en la cadena","Después, estas transacciones son verificadas por múltiples nodos de la red","A continuación, los registros son inalterables y verificables por cualquiera","Finalmente, se garantiza la trazabilidad y la confianza en el sistema"]'),
('robotica', 'eso', '{4}', '["Para crear una interfaz cerebro-ordenador, capturamos señales neuronales","Primero, unos electrodos detectan la actividad eléctrica del cerebro","Después, algoritmos interpretan estas señales para identificar intenciones","A continuación, traducen las intenciones en comandos para el ordenador","Finalmente, el usuario puede controlar dispositivos solo con el pensamiento"]'),
('robotica', 'eso', '{4}', '["La computación cuántica promete revolucionar el procesamiento de información","Primero, usa qubits que pueden estar en varios estados simultáneamente","Después, aprovecha fenómenos cuánticos como la superposición''y el entrelazamiento","A continuación, puede resolver problemas muy complejos mucho más rápido","Finalmente, transformará campos como la criptografía y la química"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de domótica integral, combinamos varios dispositivos","Primero, sensores monitorizan luz, temperatura, humedad y movimiento","Después, un controlador central procesa todos los datos recibidos","A continuación, actuadores controlan iluminación, climatización''y persianas","Finalmente, el usuario gestiona todo desde una única aplicación móvil"]'),
('robotica', 'eso', '{4}', '["Los robots quirúrgicos permiten realizar operaciones con una precisión''extraordinaria","Primero, el cirujano controla el robot desde una consola de comando","Después, los brazos robóticos reproducen sus movimientos con mayor precisión","A continuación, filtran los temblores naturales de las manos del cirujano","Finalmente, permiten cirugías menos invasivas con mejor recuperación"]'),
('robotica', 'eso', '{4}', '["Para desarrollar un robot autónomo de reparto, integramos múltiples tecnologías","Primero, el robot usa GPS y mapas para planificar la ruta óptima","Después, sensores LIDAR y cámaras le permiten evitar obstáculos dinámicos","A continuación, sistemas de inteligencia artificial interpretan el tráfico","Finalmente, entrega los paquetes en el destino sin intervención''humana"]'),
('robotica', 'eso', '{4}', '["La ciberseguridad en robótica protege los sistemas de ataques maliciosos","Primero, se implementa el cifrado de las comunicaciones entre dispositivos","Después, se establecen sistemas de autenticación para acceder a los robots","A continuación, se monitorizan los intentos de acceso no autorizado","Finalmente, se actualizan regularmente el software con parches de seguridad"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de control por gestos, usamos visión por ordenador","Primero, una cámara captura los movimientos de las manos del usuario","Después, un algoritmo identifica la posición de los dedos y la palma","A continuación, reconoce gestos predefinidos como señalar o agarrar","Finalmente, el sistema ejecuta la acción''asociada a cada gesto detectado"]'),
('robotica', 'eso', '{4}', '["Los exoesqueletos robóticos ayudan a personas con problemas de movilidad","Primero, sensores detectan la intención de movimiento del usuario","Después, motores potentes amplifican estos movimientos del cuerpo","A continuación, el usuario puede caminar o levantar objetos pesados","Finalmente, mejoran la calidad de vida de personas con discapacidad"]'),
('robotica', 'eso', '{4}', '["Para crear una simulación realista, usamos software especializado en físicas","Primero, definimos los objetos y sus propiedades físicas en el entorno virtual","Después, el motor físico calcula las interacciones entre ellos","A continuación, probamos nuestros algoritmos en este entorno seguro","Finalmente, transferimos los programas probados al robot real"]'),
('robotica', 'eso', '{4}', '["La robótica espacial permite explorar lugares inalcanzables para los humanos","Primero, los rovers han explorado la superficie de Marte durante años","Después, sondas espaciales han visitado los planetas exteriores","A continuación, los brazos robóticos construyen estructuras en órbita","Finalmente, son esenciales para la exploración del sistema solar"]'),
('robotica', 'eso', '{4}', '["Para implementar un sistema de detección de anomalías, usamos aprendizaje automático","Primero, el sistema aprende el comportamiento normal de los datos","Después, establece un perfil estadístico de este comportamiento estándar","A continuación, compara cada nueva medición con el perfil conocido","Finalmente, alerta cuando detecta una desviación significativa del patrón"]'),
('robotica', 'eso', '{4}', '["El procesamiento en el borde reduce la latencia y el ancho de banda necesario","Primero, los datos se procesan cerca de donde se generan","Después, solo se envían los resultados relevantes al servidor central","A continuación, esto reduce el tráfico de red significativamente","Finalmente, permite respuestas más rápidas en aplicaciones críticas"]'),
('robotica', 'eso', '{4}', '["Para desarrollar una plataforma de robótica educativa, consideramos varios aspectos","Primero, diseñamos una interfaz accesible para estudiantes de diferentes edades","Después, creamos un entorno de programación visual intuitivo","A continuación, ofrecemos proyectos progresivos con nivel creciente de dificultad","Finalmente, incluimos una comunidad donde compartir soluciones e ideas"]'),
('robotica', 'eso', '{4}', '["Los microrrobots tienen aplicaciones médicas muy prometedoras para el futuro","Primero, pueden entrar en el cuerpo humano por vasos sanguíneos","Después, viajan hasta la zona afectada guiados por campos magnéticos","A continuación, realizan tratamientos localizados con gran precisión","Finalmente, reducen los efectos secundarios comparados con tratamientos tradicionales"]'),
('robotica', 'eso', '{4}', '["Para crear un sistema de clasificación''automática, entrenamos un modelo","Primero, recogemos muchas imágenes etiquetadas de los objetos a clasificar","Después, entrenamos una red neuronal con estas imágenes","A continuación, el modelo aprende a distinguir entre las diferentes clases","Finalmente, clasifica objetos nuevos con una alta precisión"]'),
('robotica', 'eso', '{4}', '["La sostenibilidad en robótica considera el impacto ambiental de los dispositivos","Primero, se diseñan robots con materiales reciclables y duraderos","Después, se optimiza el consumo energético durante su funcionamiento","A continuación, se planifica el fin de vida útil del producto","Finalmente, se buscan soluciones que beneficien al medio ambiente"]'),
('robotica', 'eso', '{4}', '["Para integrar sistemas de energía renovable con robótica, combinamos varios elementos","Primero, paneles solares generan electricidad durante el día","Después, baterías almacenan la energía para usarla cuando sea necesaria","A continuación, un controlador inteligente gestiona el flujo de energía","Finalmente, los robots funcionan con energía limpia y renovable"]'),
('robotica', 'eso', '{4}', '["Los sistemas de traducción''automática usan técnicas avanzadas de inteligencia artificial","Primero, el sistema analiza el texto original identificando su estructura","Después, un modelo entrenado con millones de textos traduce las frases","A continuación, se ajusta la traducción para respetar el contexto","Finalmente, obtenemos un texto traducido con una calidad muy aceptable"]'),
('robotica', 'eso', '{4}', '["Para realizar un análisis de sentimientos en textos, aplicamos técnicas específicas","Primero, el algoritmo analiza las palabras y expresiones del texto","Después, identifica el tono emocional positivo, negativo o neutro","A continuación, calcula una puntuación global de sentimiento","Finalmente, se usa para analizar opiniones en redes sociales"]'),
('robotica', 'eso', '{4}', '["La impresión tres D''en metal está revolucionando la fabricación''industrial moderna","Primero, un láser fusiona polvo metálico capa por capa","Después, se construyen piezas con geometrías imposibles de mecanizar","A continuación, se reducen los residuos comparados con métodos tradicionales","Finalmente, se fabrican componentes personalizados bajo demanda"]'),
('robotica', 'eso', '{4}', '["Para finalizar un proyecto de robótica, documentamos todo el trabajo realizado","Primero, escribimos una memoria con los objetivos y desarrollo del proyecto","Después, incluimos los esquemas, código fuente y planos de las piezas","A continuación, preparamos una presentación con los resultados principales","Finalmente, mostramos el funcionamiento del prototipo ante el tribunal"]');
